// ── SELETOR DE ANDAR CENTRALIZADO ─────────────
function AndarSelect({ value, onChange, config, pecas, style, placeholder }) {
  const andaresCustm = config?.andaresCustm || [];
  const andaresDaBase = [...new Set(pecas.map(p=>p.andar))];
  const ordemConf = config?.ordemAndares || [];
  const todosAndares = ordenarAndares(
    [...new Set([...andaresDaBase, ...andaresCustm])],
    ordemConf
  );
  return(
    <select className={s.formSelect} value={value} onChange={onChange} style={style}>
      <option value="">{placeholder||'— selecione o andar —'}</option>
      {todosAndares.map(a=><option key={a} value={a}>{a}</option>)}
    </select>
  );
}

function ModalConfig({ open, onClose, pecas, config, onSalvar }) {
  const andaresDaBase = [...new Set(pecas.map(p=>p.andar))];
  const ordemAtual = config.ordemAndares || [];
  const [ordem, setOrdem] = useState([]);
  const [nomeObra, setNomeObra] = useState('');
  const [novoAndar, setNovoAndar] = useState('');

  useEffect(()=>{
    if(open){
      // Inclui andares das peças + andares customizados que não têm peças ainda
      const todosAndares = [...new Set([...andaresDaBase, ...(config.andaresCustm||[])])];
      const ord = ordenarAndares(todosAndares, ordemAtual);
      setOrdem(ord);
      setNomeObra(config.nomeObra||'');
    }
  },[open]);

  function adicionarAndar(){
    const a = novoAndar.trim();
    if(!a||ordem.includes(a)) return;
    setOrdem(prev=>[...prev, a]);
    setNovoAndar('');
  }

  function removerAndar(a){
    if(andaresDaBase.includes(a)){
      // Tem peças — pode remover da lista de ordenação mas peças ficam com o andar
      if(!confirm(`O andar "${a}" tem peças cadastradas.\nRemover da lista de andares não exclui as peças — elas continuarão existindo com este andar.\n\nDeseja remover "${a}" da lista mesmo assim?`)) return;
    } else {
      if(!confirm(`Remover o andar "${a}" da lista?`)) return;
    }
    setOrdem(prev=>prev.filter(x=>x!==a));
  }

  const [dragIdx, setDragIdx] = useState(null);

  function mover(i, dir) {
    const nova=[...ordem];
    const j=i+dir;
    if(j<0||j>=nova.length) return;
    [nova[i],nova[j]]=[nova[j],nova[i]];
    setOrdem(nova);
  }

  function inverter() { setOrdem(prev=>[...prev].reverse()); }

  function onDragStart(i) { setDragIdx(i); }
  function onDragOver(e,i) {
    e.preventDefault();
    if(dragIdx===null||dragIdx===i) return;
    const nova=[...ordem];
    const item=nova.splice(dragIdx,1)[0];
    nova.splice(i,0,item);
    setOrdem(nova);
    setDragIdx(i);
  }
  function onDragEnd() { setDragIdx(null); }

  function salvar(){
    const andaresCustm = ordem.filter(a=>!andaresDaBase.includes(a));
    onSalvar({...config, nomeObra, ordemAndares:ordem, andaresCustm});
    onClose();
  }

  return(
    <Modal open={open} onClose={onClose} title="⚙ Configuração da Obra" wide>
      <div className={s.formGroup} style={{marginBottom:20}}>
        <label className={s.formLabel}>Nome da Obra</label>
        <input className={s.formInput} placeholder="ex: Residencial Solar" value={nomeObra} onChange={e=>setNomeObra(e.target.value)}/>
      </div>

      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:10}}>
        <div className={s.sectionTitle} style={{marginBottom:0,flex:1}}>Ordem dos Andares</div>
        <button onClick={inverter} className={s.btnAction} style={{padding:'6px 14px',fontSize:12}}>⇅ Inverter ordem</button>
      </div>
      {/* Campo para adicionar novo andar */}
      <div style={{display:'flex',gap:8,marginBottom:12}}>
        <input className={s.formInput} placeholder="Adicionar andar (ex: 2º Subsolo, Cobertura...)"
          value={novoAndar} onChange={e=>setNovoAndar(e.target.value)}
          onKeyDown={e=>e.key==='Enter'&&adicionarAndar()} style={{flex:1}}/>
        <button className={s.btnPrimary} onClick={adicionarAndar} style={{padding:'10px 20px',whiteSpace:'nowrap',fontSize:13}}>+ Adicionar</button>
      </div>
      <div style={{fontFamily:'var(--mono)',fontSize:11,color:'var(--text3)',marginBottom:10}}>Arraste para reordenar · ▲▼ para mover · ✕ remove andares sem peças</div>
      <div style={{background:'var(--surface2)',border:'1px solid var(--border)',borderRadius:'var(--radius-sm)',marginBottom:16}}>
        {ordem.length===0
          ?<div className={s.empty}>Nenhum andar cadastrado ainda.</div>
          :ordem.map((a,i)=>(
            <div key={a}
              draggable
              onDragStart={()=>onDragStart(i)}
              onDragOver={e=>onDragOver(e,i)}
              onDragEnd={onDragEnd}
              style={{display:'flex',alignItems:'center',gap:12,padding:'12px 16px',
                borderBottom:i<ordem.length-1?'1px solid var(--border)':'none',
                background:dragIdx===i?'rgba(245,197,24,0.08)':'transparent',
                cursor:'grab',transition:'background 0.1s',userSelect:'none'}}>
              <span style={{color:'var(--text3)',fontSize:14}}>⠿</span>
              <span style={{fontFamily:'var(--mono)',fontSize:12,color:'var(--text3)',width:24,textAlign:'right'}}>{i+1}</span>
              <span style={{flex:1,fontWeight:600,fontSize:14}}>{a}</span>
              <button onClick={()=>mover(i,-1)} disabled={i===0} style={{background:'none',border:'1px solid var(--border)',borderRadius:4,color:'var(--text2)',padding:'4px 10px',cursor:'pointer',fontSize:12,opacity:i===0?0.3:1}}>▲</button>
              <button onClick={()=>mover(i,1)} disabled={i===ordem.length-1} style={{background:'none',border:'1px solid var(--border)',borderRadius:4,color:'var(--text2)',padding:'4px 10px',cursor:'pointer',fontSize:12,opacity:i===ordem.length-1?0.3:1}}>▼</button>
              <button onClick={()=>removerAndar(a)} title={andaresDaBase.includes(a)?'Tem peças — exclua as peças primeiro':'Remover andar'}
                style={{background:'none',border:'1px solid var(--border)',borderRadius:4,color:andaresDaBase.includes(a)?'var(--text3)':'var(--red)',padding:'4px 8px',cursor:'pointer',fontSize:11,opacity:andaresDaBase.includes(a)?0.3:1}}>✕</button>
            </div>
          ))
        }
      </div>
      <div className={s.btnRow}>
        <button className={s.btnSecondary} onClick={onClose}>Cancelar</button>
        <button className={s.btnPrimary} onClick={salvar}>✓ Salvar Configuração</button>
      </div>
    </Modal>
  );
}

// ════════════════════════════════════════════════
// MODAL: GERENCIAR PEÇAS
// ════════════════════════════════════════════════
function ModalPecas({ open, onClose, pecas, onSalvo }) {
  const [modo,setModo]=useState('lista');
  const [editPeca,setEditPeca]=useState(null);
  const [filtro,setFiltro]=useState('');
  const [salvando,setSalvando]=useState(false);
  const [erro,setErro]=useState('');
  const [nome,setNome]=useState(''); const [tipo,setTipo]=useState('Pilar');
  const [andar,setAndar]=useState(''); const [volume,setVolume]=useState('');
  const [textoImport,setTextoImport]=useState('');
  const [termoBusca,setTermoBusca]=useState('');
  const [andarBusca,setAndarBusca]=useState('todos');
  const [previewImport,setPreviewImport]=useState([]);
  const [erroImport,setErroImport]=useState('');

  const [buscaNome, setBuscaNome] = useState('');
  const [buscaSel, setBuscaSel]  = useState(null); // peça selecionada na busca
  useEffect(()=>{ if(open){setModo('lista');setFiltro('');setErro('');setBuscaNome('');setBuscaSel(null);} },[open]);
  const andares=[...new Set(pecas.map(p=>p.andar))].sort();
  const pecasFilt=pecas.filter(p=>p.nome.toLowerCase().includes(filtro.toLowerCase())||p.andar.toLowerCase().includes(filtro.toLowerCase())||p.tipo.toLowerCase().includes(filtro.toLowerCase()));

  function abrirEditar(p){setEditPeca(p);setNome(p.nome);setTipo(p.tipo);setAndar(p.andar);setVolume(String(p.volume));setErro('');setModo('editar');}
  function abrirNova(){setEditPeca(null);setNome('');setTipo('Pilar');setAndar('');setVolume('');setErro('');setModo('nova');}

  async function salvarPeca(){
    if(!nome||!andar||!volume){setErro('Preencha todos os campos');return;}
    setSalvando(true);
    try{
      if(modo==='editar'){await apiEditarPeca({id:editPeca.id,nome,tipo,andar,volume});onSalvo(`✓ "${nome}" atualizada!`);}
      else{await apiAdicionarPeca({nome,tipo,andar,volume});onSalvo(`✓ "${nome}" adicionada!`);}
      setModo('lista');
    }catch(e){setErro('Erro: '+e.message);}finally{setSalvando(false);}
  }

  async function excluir(p){
    if(!confirm(`Excluir "${p.nome}"?`)) return;
    setSalvando(true);
    try{await apiExcluirPeca(p.id);onSalvo(`"${p.nome}" excluída.`);}
    catch(e){setErro('Erro: '+e.message);}finally{setSalvando(false);}
  }

  function gerarExcel(){
    const header='Nome\tTipo\tAndar\tVolume (m³)\n';
    const exemplo='Pilar P-01\tPilar\tTérreo\t1.5\nViga V-01\tViga\tTérreo\t2.8\nLaje L-01\tLaje\t1º Pavimento\t12.4';
    const blob=new Blob([header+exemplo],{type:'text/tab-separated-values'});
    const url=URL.createObjectURL(blob);
    const a=document.createElement('a');a.href=url;a.download='base_pecas.tsv';a.click();URL.revokeObjectURL(url);
  }

  // Normaliza nome do andar: "1º SUBSOLO", "1o subsolo", "1� SUBSOLO" → "1º Subsolo"
  function normalizarAndar(a){
    if(!a) return 'Sem andar';
    // Corrige encoding quebrado: o → º, a → ª
    let s = a.trim()
      .replace(/([0-9]+)\s*o/gi, '$1º')
      .replace(/([0-9]+)\s*a/gi, '$1ª')
      .replace(/�/g, 'º')
      .replace(/\?/g, 'º');
    // Padroniza capitalização: primeira letra maiúscula, resto minúsculo
    s = s.toLowerCase()
      .replace(/(^\w|\s\w)/g, c => c.toUpperCase())
      .replace(/Subsolo/, 'Subsolo')
      .replace(/Pavimento/, 'Pavimento');
    // Casos especiais
    s = s.replace(/Terreo/i, 'Térreo')
         .replace(/TERREO/i, 'Térreo')
         .replace(/Térreo/i, 'Térreo');
    return s.trim();
  }

  function parsearImport(txt){
    setErroImport('');
    const linhas=txt.trim().split(/\r?\n/).filter(l=>l.trim());
    const ps=[],errs=[];
    linhas.forEach((linha,i)=>{
      if(i===0&&linha.toLowerCase().includes('nome')) return;
      const cols=linha.split('\t');
      const [n,t,a,vRaw]=(cols.map(c=>c.trim()));
      if(!n||n==='') return;
      if(n.toLowerCase()==='nome') return;
      const v=parseFloat((vRaw||'').replace(',','.'));
      if(isNaN(v)||v<=0) return;
      ps.push({nome:n, tipo:t||'Viga', andar:normalizarAndar(a), volume:v});
    });
    if(ps.length===0){setErroImport('Nenhuma linha válida encontrada. Verifique o formato.');setPreviewImport([]);return;}
    setPreviewImport(ps);
  }

  function parsearArquivo(file){
    if(!file) return;
    setErroImport('');
    const reader = new FileReader();
    reader.onload = (e) => {
      let txt = e.target.result;
      // Se detectar caracteres quebrados típicos de Latin-1, relê com encoding correto
      if(txt.includes('\uFFFD') || /[\x80-\x9F]/.test(txt)) {
        const reader2 = new FileReader();
        reader2.onload = (e2) => { parsearImport(e2.target.result); };
        reader2.readAsText(file, 'windows-1252');
        return;
      }
      parsearImport(txt);
    };
    reader.readAsText(file, 'UTF-8');
  }

  async function salvarImport(){
    if(!previewImport.length) return;
    setSalvando(true);
    try{await apiAdicionarPecaLote(previewImport);onSalvo(`✓ ${previewImport.length} peças importadas!`);setModo('lista');setTextoImport('');setPreviewImport([]);}
    catch(e){setErroImport('Erro: '+e.message);}finally{setSalvando(false);}
  }

  return(
    <Modal open={open} onClose={onClose} title="⬡ Gerenciar Peças" wide>
      {modo==='lista'&&(
        <div>
          <div style={{display:'flex',gap:10,marginBottom:16,flexWrap:'wrap'}}>
            <input className={s.formInput} style={{flex:1,minWidth:160}} placeholder="Buscar peça..." value={filtro} onChange={e=>setFiltro(e.target.value)}/>
            <button className={s.btnAction} onClick={abrirNova}>+ Nova</button>
            <button className={s.btnAction} onClick={()=>{setModo('importar');setTextoImport('');setPreviewImport([]);setErroImport('');}}>⊞ Importar Lote</button>
          </div>
          {erro&&<div className={s.alertRed} style={{marginBottom:10}}>{erro}</div>}
          <div style={{maxHeight:420,overflowY:'auto',border:'1px solid var(--border)'}}>
            {pecasFilt.length===0?<div className={s.empty}>Nenhuma peça.</div>
              :pecasFilt.map(p=>(
                <div key={p.id} style={{display:'flex',alignItems:'center',gap:12,padding:'12px 16px',borderBottom:'1px solid var(--border)'}}>
                  <div style={{flex:1}}><div style={{fontWeight:600,fontSize:15}}>{p.nome}</div><div style={{fontFamily:'var(--mono)',fontSize:12,color:'var(--text3)',marginTop:2}}>{p.tipo} · {p.andar} · {fmt4(p.volume)} m³</div></div>
                  <button className={s.btnAction} style={{padding:'6px 14px',fontSize:12}} onClick={()=>abrirEditar(p)}>Editar</button>
                  <button className={s.btnDanger} onClick={()=>excluir(p)}>✕</button>
                </div>
              ))
            }
          </div>
          <div className={s.btnRow}><button className={s.btnSecondary} onClick={onClose}>Fechar</button></div>
        </div>
      )}


      {(modo==='nova'||modo==='editar')&&(
        <div>
          <div style={{marginBottom:14,fontFamily:'var(--mono)',fontSize:12,color:'var(--text3)'}}>{modo==='editar'?`Editando: ${editPeca.nome}`:'Nova peça'}</div>
          {erro&&<div className={s.alertRed} style={{marginBottom:12}}>{erro}</div>}
          <div className={s.formGrid}>
            <div className={s.formGroup}><label className={s.formLabel}>Nome</label><input className={s.formInput} placeholder="ex: Pilar P-01" value={nome} onChange={e=>setNome(e.target.value)}/></div>
            <div className={s.formGroup}><label className={s.formLabel}>Tipo</label><select className={s.formSelect} value={tipo} onChange={e=>setTipo(e.target.value)}>{TIPOS.map(t=><option key={t}>{t}</option>)}</select></div>
            <div className={s.formGroup}><label className={s.formLabel}>Andar</label><input className={s.formInput} placeholder="ex: Térreo" value={andar} onChange={e=>setAndar(e.target.value)} list="al"/><datalist id="al">{andares.map(a=><option key={a} value={a}/>)}</datalist></div>
            <div className={s.formGroup}><label className={s.formLabel}>Volume (m³)</label><input className={s.formInput} type="number" step="0.0001" min="0.0001" placeholder="0.0000" value={volume} onChange={e=>setVolume(e.target.value)}/></div>
          </div>
          <div className={s.btnRow}>
            <button className={s.btnSecondary} onClick={()=>setModo('lista')}>← Voltar</button>
            <button className={s.btnPrimary} disabled={salvando} onClick={salvarPeca}>{salvando?'⏳ Salvando...':(modo==='editar'?'Salvar':'Cadastrar')}</button>
          </div>
        </div>
      )}

      {modo==='buscar'&&(
        <div>
          <div style={{marginBottom:16}}>
            <label className={s.formLabel} style={{display:'block',marginBottom:6}}>Nome da peça</label>
            <input className={s.formInput} placeholder="ex: Pilar P-01, Viga V-..." value={termoBusca} autoFocus
              onChange={e=>setTermoBusca(e.target.value)}/>
          </div>
          {(()=>{
            const termo = termoBusca.toLowerCase().trim();
            if(!termo) return <div className={s.empty}>Digite o nome da peça para buscar</div>;
            const encontradas = pecas.filter(p=>p.nome.toLowerCase().includes(termo));
            if(!encontradas.length) return <div className={s.empty}>Nenhuma peça encontrada com "{termoBusca}"</div>;
            // Agrupar por nome base (ignorando andar)
            const grupos = {};
            encontradas.forEach(p=>{
              const k = p.nome;
              if(!grupos[k]) grupos[k]=[];
              grupos[k].push(p);
            });
            return(
              <div style={{maxHeight:380,overflowY:'auto',border:'1px solid var(--border)',borderRadius:'var(--radius-sm)'}}>
                {Object.entries(grupos).map(([nome,ps])=>(
                  <div key={nome} style={{borderBottom:'1px solid var(--border)'}}>
                    <div style={{padding:'10px 16px',background:'var(--surface2)',fontWeight:700,fontSize:14,color:'var(--text)'}}>{nome}</div>
                    {ps.map(p=>{
                      const vc = typeof volLancadoPeca==='function' ? 0 : 0; // será calculado no dashboard
                      return(
                        <div key={p.id} style={{display:'flex',alignItems:'center',justifyContent:'space-between',padding:'10px 20px',borderTop:'1px solid var(--border)'}}>
                          <div>
                            <div style={{fontSize:13,color:'var(--text2)'}}>{p.andar} · {p.tipo}</div>
                            <div style={{fontFamily:'var(--mono)',fontSize:12,color:'var(--text3)',marginTop:2}}>
                              Volume: <span style={{color:'var(--accent)'}}>{p.volume} m³</span>
                            </div>
                          </div>
                          <div style={{display:'flex',gap:8}}>
                            <button className={s.btnAction} style={{padding:'5px 12px',fontSize:12}} onClick={()=>abrirEditar(p)}>Editar</button>
                            <button className={s.btnDanger} onClick={()=>excluir(p)}>✕</button>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                ))}
              </div>
            );
          })()}
          <div className={s.btnRow}>
            <button className={s.btnSecondary} onClick={()=>{setModo('lista');setTermoBusca('');}}>← Voltar</button>
          </div>
        </div>
      )}

      {modo==='importar'&&(
        <div>
          <div className={s.infoBox} style={{marginBottom:14}}>
            <strong>Como usar:</strong> Cole do Excel as colunas: Nome | Tipo | Andar | Volume(m³)<br/>
            Ou baixe o arquivo base abaixo para preencher corretamente.
          </div>
          {/* Ações de importação */}
          <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:10,marginBottom:14}}>
            <button className={s.btnSecondary} onClick={gerarExcel} style={{display:'flex',alignItems:'center',justifyContent:'center',gap:8,padding:'12px'}}>
              ⬇ Baixar Modelo Excel
            </button>
            <label style={{display:'flex',alignItems:'center',justifyContent:'center',gap:8,padding:'12px',background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:'var(--radius-sm)',color:'var(--text2)',fontSize:13,fontWeight:600,cursor:'pointer',transition:'all 0.15s'}}
              onMouseOver={e=>{e.currentTarget.style.borderColor='var(--accent)';e.currentTarget.style.color='var(--accent)';}}
              onMouseOut={e=>{e.currentTarget.style.borderColor='var(--border)';e.currentTarget.style.color='var(--text2)';}}>
              📂 Carregar Arquivo (TSV/CSV)
              <input type="file" accept=".tsv,.csv,.txt,.xls,.xlsx" style={{display:'none'}} onChange={e=>parsearArquivo(e.target.files[0])}/>
            </label>
          </div>

          <div style={{textAlign:'center',color:'var(--text3)',fontSize:12,marginBottom:10}}>— ou cole o conteúdo abaixo —</div>

          {erroImport&&<div className={s.alertRed} style={{marginBottom:10}}>{erroImport}</div>}
          <textarea style={{width:'100%',height:130,background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:'var(--radius-sm)',color:'var(--text)',fontFamily:'var(--mono)',fontSize:13,padding:'12px 16px',outline:'none',resize:'vertical',lineHeight:1.8}}
            placeholder={'V201\tVIGA\t1º subsolo\t3,17\nV202\tVIGA\t1º subsolo\t1,32'}
            value={textoImport} onChange={e=>{setTextoImport(e.target.value);parsearImport(e.target.value);}}/>
          {previewImport.length>0&&(
            <div style={{marginTop:10,maxHeight:200,overflowY:'auto',border:'1px solid var(--border)'}}>
              <table className={s.table}><thead><tr><th>#</th><th>Nome</th><th>Tipo</th><th>Andar</th><th>m³</th></tr></thead>
                <tbody>{previewImport.map((p,i)=><tr key={i}><td className={s.tdMuted}>{i+1}</td><td style={{fontWeight:600}}>{p.nome}</td><td className={s.tdMono}>{p.tipo}</td><td className={s.tdMono}>{p.andar}</td><td className={s.tdAccent}>{fmt4(p.volume)}</td></tr>)}</tbody>
              </table>
            </div>
          )}
          <div className={s.btnRow}>
            <button className={s.btnSecondary} onClick={()=>setModo('lista')}>← Voltar</button>
            <button className={s.btnPrimary} disabled={!previewImport.length||salvando} onClick={salvarImport}>{salvando?'⏳...':`✓ Importar ${previewImport.length} peças`}</button>
          </div>
        </div>
      )}
    </Modal>
  );
}

// ════════════════════════════════════════════════
// MODAL: CONCRETAGEM
// ════════════════════════════════════════════════
function ModalConcretagem({ open, onClose, pecas, concretagens, pecaConc, btsConfig, onSalvo }) {
  const [subModo,setSubModo]=useState('menu');
  const [step,setStep]=useState(1);
  const [concSel,setConcSel]=useState('');
  const [concId,setConcId]=useState('');
  const [numero,setNumero]=useState('');
  const [data,setData]=useState('');
  const [desc,setDesc]=useState('');
  const [vinculos,setVinculos]=useState([]);
  const [bts,setBts]=useState([]);
  const [filtroAndar,setFiltroAndar]=useState('todos');
  const [filtroTipo,setFiltroTipo]=useState('todos');
  const [buscaPeca,setBuscaPeca]=useState('');
  const [salvando,setSalvando]=useState(false);
  const [erro,setErro]=useState('');
  const genId=p=>`${p}_${Date.now()}_${Math.random().toString(36).slice(2,6)}`;
  const andares=['todos',...new Set(pecas.map(p=>p.andar))].sort();
  const tipos=['todos',...new Set(pecas.map(p=>p.tipo))].sort();

  useEffect(()=>{ if(open){setSubModo('menu');setErro('');} },[open]);

  async function excluirConc(){
    if(!concSel){setErro('Selecione uma concretagem para excluir');return;}
    const c=concretagens.find(x=>x.id===concSel);
    if(!c)return;
    if(!confirm(`Excluir Concretagem Nº${c.numero}? Isso removerá todas as peças vinculadas e BTs configuradas.`))return;
    setSalvando(true);
    try{
      await apiExcluirConcretagem(c.id);
      onSalvo(`Concretagem Nº${c.numero} excluída.`);
      setConcSel('');
      onClose();
    }catch(e){setErro('Erro ao excluir: '+e.message);}
    finally{setSalvando(false);}
  }

  function iniciarNova(){setConcId(genId('c'));setNumero(String(concretagens.length+1));setData(new Date().toISOString().slice(0,10));setDesc('');setVinculos([]);setBts([]);setErro('');setStep(1);setFiltroAndar('todos');setFiltroTipo('todos');setSubModo('nova');}
  function iniciarEditar(){
    if(!concSel){setErro('Selecione uma concretagem');return;}
    const c=concretagens.find(x=>x.id===concSel);if(!c)return;
    setConcId(c.id);setNumero(String(c.numero));setData(c.data);setDesc(c.descricao||'');
    setVinculos(pecaConc.filter(pc=>pc.concretagemId===c.id).map(pc=>({pecaId:pc.pecaId,pctConcretagem:pc.pctConcretagem,id:pc.id})));
    setBts(btsConfig.filter(b=>b.concretagemId===c.id).map(b=>({...b})));
    setErro('');setStep(1);setFiltroAndar('todos');setFiltroTipo('todos');setSubModo('editar');
  }

  function togglePeca(pecaId){setVinculos(prev=>{if(prev.find(v=>v.pecaId===pecaId))return prev.filter(v=>v.pecaId!==pecaId);return[...prev,{pecaId,pctConcretagem:100}];});}
  function setPct(pecaId,val){setVinculos(prev=>prev.map(v=>v.pecaId===pecaId?{...v,pctConcretagem:parseFloat(val)||100}:v));}
  function toggleAndar(andar){const ids=pecas.filter(p=>p.andar===andar).map(p=>p.id);const todos=ids.every(id=>vinculos.find(v=>v.pecaId===id));if(todos)setVinculos(prev=>prev.filter(v=>!ids.includes(v.pecaId)));else{const novos=ids.filter(id=>!vinculos.find(v=>v.pecaId===id)).map(id=>({pecaId:id,pctConcretagem:100}));setVinculos(prev=>[...prev,...novos]);}}
  function addBT(){setBts(prev=>[...prev,{id:'',numero:prev.length+1,volumePrevisto:8,notaFiscal:'',codigoBT:''}]);}
  function remBT(i){setBts(prev=>prev.filter((_,idx)=>idx!==i));}
  function updBT(i,f,v){setBts(prev=>prev.map((b,idx)=>idx===i?{...b,[f]:v}:b));}

  const volTotalVinculos=vinculos.reduce((s,v)=>{const p=pecas.find(x=>x.id===v.pecaId);return s+(p?(v.pctConcretagem/100)*p.volume:0);},0);
  const volTotalBTs=bts.reduce((s,b)=>s+(parseFloat(b.volumePrevisto)||0),0);
  const pecasVisiveis=pecas.filter(p=>(filtroAndar==='todos'||p.andar===filtroAndar)&&(filtroTipo==='todos'||p.tipo===filtroTipo)&&(!buscaPeca||p.nome.toLowerCase().includes(buscaPeca.toLowerCase())));

  async function salvar(){
    if(!numero||!data){setErro('Preencha número e data');return;}
    if(!vinculos.length){setErro('Vincule ao menos 1 peça');return;}
    setSalvando(true);
    try{
      await apiSalvarConcretagem({id:concId,numero,data,descricao:desc,
        pecaConcs:vinculos.map(v=>({id:v.id||'',pecaId:v.pecaId,pctConcretagem:v.pctConcretagem})),
        btsConfig:bts.map(b=>({id:b.id||'',numero:b.numero,volumePrevisto:b.volumePrevisto,notaFiscal:b.notaFiscal||'',codigoBT:b.codigoBT||''})),
      });
      onSalvo(`✓ Concretagem Nº${numero} salva!`);onClose();
    }catch(e){setErro('Erro: '+e.message);}finally{setSalvando(false);}
  }

  return(
    <Modal open={open} onClose={onClose} title="◈ Concretagens" extraWide>
      {subModo==='menu'&&(
        <div>
          {erro&&<div className={s.alertRed} style={{marginBottom:14}}>{erro}</div>}
          <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:16,marginBottom:20}}>
            <div onClick={iniciarNova} className={s.menuCard}>
              <div className={s.menuCardIcon}>+</div>
              <div className={s.menuCardTitle}>Nova Concretagem</div>
              <div className={s.menuCardSub}>Criar do zero com peças e BTs</div>
            </div>
            <div className={s.menuCard} onClick={e=>e.stopPropagation()}>
              <div className={s.menuCardIcon}>✎</div>
              <div className={s.menuCardTitle}>Editar / Excluir</div>
              <div className={s.menuCardSub}>Alterar peças, BTs ou excluir</div>
              <select className={s.formSelect} style={{marginTop:12}} value={concSel} onChange={e=>setConcSel(e.target.value)}>
                <option value="">— selecione —</option>
                {[...concretagens].sort((a,b)=>a.numero-b.numero).map(c=><option key={c.id} value={c.id}>Nº{c.numero} — {c.data}{c.descricao?` | ${c.descricao}`:''}</option>)}
              </select>
              <div style={{display:'grid',gridTemplateColumns:'1fr auto',gap:8,marginTop:10}}>
                <button className={s.btnPrimary} onClick={iniciarEditar}>Editar →</button>
                <button className={s.btnDanger} onClick={excluirConc} title="Excluir concretagem">🗑</button>
              </div>
            </div>
          </div>
          <div className={s.btnRow}><button className={s.btnSecondary} onClick={onClose}>Fechar</button></div>
        </div>
      )}

      {(subModo==='nova'||subModo==='editar')&&(
        <div>
          <div className={s.steps}>
            {['Dados','Peças','BTs','Resumo'].map((label,i)=>(
              <div key={i} className={`${s.step} ${step===i+1?s.stepActive:step>i+1?s.stepDone:''}`}>
                <div className={s.stepNum}>{step>i+1?'✓':i+1}</div>
                <div className={s.stepLabel}>{label}</div>
              </div>
            ))}
          </div>
          {erro&&<div className={s.alertRed} style={{marginBottom:14}}>{erro}</div>}

          {step===1&&(
            <div>
              <div className={s.formGrid}>
                <div className={s.formGroup}><label className={s.formLabel}>Número</label><input className={s.formInput} type="number" min="1" value={numero} onChange={e=>setNumero(e.target.value)}/></div>
                <div className={s.formGroup}><label className={s.formLabel}>Data</label><input className={s.formInput} type="date" value={data} onChange={e=>setData(e.target.value)}/></div>
                <div className={`${s.formGroup} ${s.formGroupFull}`}><label className={s.formLabel}>Descrição</label><input className={s.formInput} placeholder="ex: Pilares Térreo eixos A-D" value={desc} onChange={e=>setDesc(e.target.value)}/></div>
              </div>
              <div className={s.btnRow}><button className={s.btnSecondary} onClick={()=>setSubModo('menu')}>← Voltar</button><button className={s.btnPrimary} onClick={()=>{if(!numero||!data){setErro('Preencha número e data');return;}setErro('');setStep(2);}}>Próximo →</button></div>
            </div>
          )}

          {step===2&&(
            <div>
              <div style={{display:'flex',gap:10,marginBottom:12,flexWrap:'wrap',alignItems:'center'}}>
                <span style={{fontFamily:'var(--mono)',fontSize:13,color:'var(--accent)',fontWeight:700}}>{vinculos.length} peças · {fmt4(volTotalVinculos)} m³</span>
                {filtroAndar!=='todos'&&<button className={s.btnAction} style={{padding:'6px 14px',fontSize:12}} onClick={()=>toggleAndar(filtroAndar)}>{pecas.filter(p=>p.andar===filtroAndar).every(p=>vinculos.find(v=>v.pecaId===p.id))?'Desmarcar tudo do andar':'Marcar tudo do andar'}</button>}
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:8,marginBottom:12}}>
                <select className={s.formSelect} value={filtroAndar} onChange={e=>setFiltroAndar(e.target.value)}>{andares.map(a=><option key={a} value={a}>{a==='todos'?'Todos os andares':a}</option>)}</select>
                <select className={s.formSelect} value={filtroTipo} onChange={e=>setFiltroTipo(e.target.value)}>{tipos.map(t=><option key={t} value={t}>{t==='todos'?'Todos os tipos':t}</option>)}</select>
                <input className={s.formInput} placeholder="🔍 Buscar por nome..." value={buscaPeca} onChange={e=>setBuscaPeca(e.target.value)}/>
              </div>
              <div style={{maxHeight:320,overflowY:'auto',border:'1px solid var(--border)'}}>
                {pecasVisiveis.length===0?<div className={s.empty}>Nenhuma peça.</div>
                  :pecasVisiveis.map(p=>{const sel=!!vinculos.find(v=>v.pecaId===p.id);const vinc=vinculos.find(v=>v.pecaId===p.id);return(
                    <div key={p.id} style={{display:'flex',alignItems:'center',gap:12,padding:'12px 16px',borderBottom:'1px solid var(--border)',background:sel?'rgba(232,162,37,0.06)':'transparent'}}>
                      <div onClick={()=>togglePeca(p.id)} style={{width:22,height:22,border:`2px solid ${sel?'var(--accent)':'var(--border2)'}`,background:sel?'var(--accent)':'transparent',display:'flex',alignItems:'center',justifyContent:'center',cursor:'pointer',flexShrink:0,fontSize:14,color:'#0e0f11',fontWeight:700,transition:'all 0.15s'}}>{sel?'✓':''}</div>
                      <div style={{flex:1,cursor:'pointer'}} onClick={()=>togglePeca(p.id)}><div style={{fontWeight:600,fontSize:15}}>{p.nome}</div><div style={{fontFamily:'var(--mono)',fontSize:12,color:'var(--text3)',marginTop:2}}>{p.tipo} · {p.andar} · {fmt4(p.volume)} m³</div></div>
                      {sel&&<div style={{display:'flex',alignItems:'center',gap:8,flexShrink:0}}>
                        <label style={{fontFamily:'var(--mono)',fontSize:11,color:'var(--text3)'}}>%</label>
                        <input type="number" min="1" max="100" step="1" value={vinc.pctConcretagem} onChange={e=>setPct(p.id,e.target.value)} onClick={e=>e.stopPropagation()} style={{width:64,background:'var(--surface2)',border:'1px solid var(--accent)',color:'var(--accent)',fontFamily:'var(--mono)',fontSize:13,padding:'6px 8px',outline:'none'}}/>
                        <span style={{fontFamily:'var(--mono)',fontSize:12,color:'var(--text3)'}}>{fmt4((vinc.pctConcretagem/100)*p.volume)} m³</span>
                      </div>}
                    </div>
                  );})}
              </div>
              <div className={s.btnRow}><button className={s.btnSecondary} onClick={()=>{setErro('');setStep(1);}}>← Voltar</button><button className={s.btnPrimary} onClick={()=>{if(!vinculos.length){setErro('Vincule ao menos 1 peça');return;}setErro('');setStep(3);}}>Próximo →</button></div>
            </div>
          )}

          {step===3&&(
            <div>
              <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:14,flexWrap:'wrap',gap:8}}>
                <div style={{fontFamily:'var(--mono)',fontSize:13,color:'var(--text2)'}}>
                  Volume concretagem: <span style={{color:'var(--accent)',fontWeight:700}}>{fmt4(volTotalVinculos)} m³</span>
                  {bts.length>0&&<> · BTs: <span style={{color:Math.abs(volTotalBTs-volTotalVinculos)<0.1?'var(--green)':'var(--red)',fontWeight:700}}>{fmt4(volTotalBTs)} m³</span></>}
                </div>
                <button className={s.btnAction} style={{padding:'8px 18px',fontSize:13}} onClick={addBT}>+ Adicionar BT</button>
              </div>
              {bts.length===0?<div className={s.empty}>Clique em "+ Adicionar BT".</div>
                :<div style={{maxHeight:340,overflowY:'auto'}}>
                  {bts.map((b,i)=>(
                    <div key={i} style={{display:'grid',gridTemplateColumns:'70px 130px 1fr 1fr auto',gap:10,marginBottom:10,alignItems:'end'}}>
                      <div className={s.formGroup}><label className={s.formLabel}>BT Nº</label><input className={s.formInput} type="number" min="1" value={b.numero} onChange={e=>updBT(i,'numero',e.target.value)}/></div>
                      <div className={s.formGroup}><label className={s.formLabel}>Volume (m³)</label><input className={s.formInput} type="number" step="0.5" min="0" value={b.volumePrevisto} onChange={e=>updBT(i,'volumePrevisto',e.target.value)}/></div>
                      <div className={s.formGroup}><label className={s.formLabel}>Nota Fiscal</label><input className={s.formInput} placeholder="opcional" value={b.notaFiscal} onChange={e=>updBT(i,'notaFiscal',e.target.value)}/></div>
                      <div className={s.formGroup}><label className={s.formLabel}>Código BT</label><input className={s.formInput} placeholder="opcional" value={b.codigoBT} onChange={e=>updBT(i,'codigoBT',e.target.value)}/></div>
                      <button className={s.btnDanger} style={{marginBottom:2}} onClick={()=>remBT(i)}>✕</button>
                    </div>
                  ))}
                </div>
              }
              <div className={s.btnRow}><button className={s.btnSecondary} onClick={()=>{setErro('');setStep(2);}}>← Voltar</button><button className={s.btnPrimary} onClick={()=>{setErro('');setStep(4);}}>Revisar →</button></div>
            </div>
          )}

          {step===4&&(
            <div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:14,marginBottom:18}}>
                <div className={s.kpi}><div className={s.kpiLabel}>Concretagem</div><div className={s.kpiValue} style={{fontSize:30}}>Nº {numero}</div><div className={s.kpiSub}>{data}{desc&&` · ${desc}`}</div></div>
                <div className={`${s.kpi} ${s.kpiGreen}`}><div className={s.kpiLabel}>Volume Total</div><div className={s.kpiValue} style={{fontSize:30}}>{fmt4(volTotalVinculos)}<span className={s.kpiUnit}>m³</span></div><div className={s.kpiSub}>{vinculos.length} peças · {bts.length} BTs</div></div>
              </div>
              <div style={{marginBottom:14}}>{vinculos.slice(0,6).map(v=>{const p=pecas.find(x=>x.id===v.pecaId);return p?<div key={v.pecaId} style={{display:'flex',justifyContent:'space-between',padding:'7px 0',borderBottom:'1px solid var(--border)',fontFamily:'var(--mono)',fontSize:13}}><span>{p.nome} ({p.andar})</span><span style={{color:'var(--accent)'}}>{v.pctConcretagem}% → {fmt4((v.pctConcretagem/100)*p.volume)} m³</span></div>:null;})}
                {vinculos.length>6&&<div style={{fontFamily:'var(--mono)',fontSize:12,color:'var(--text3)',marginTop:4}}>... e mais {vinculos.length-6} peças</div>}
              </div>
              {bts.length>0&&<div style={{marginBottom:14}}>{bts.map((b,i)=><div key={i} style={{display:'flex',justifyContent:'space-between',padding:'7px 0',borderBottom:'1px solid var(--border)',fontFamily:'var(--mono)',fontSize:13}}><span style={{color:'var(--accent)'}}>BT-{b.numero}</span><span>{fmt4(b.volumePrevisto)} m³{b.notaFiscal?` · NF:${b.notaFiscal}`:''}</span></div>)}</div>}
              <div className={s.btnRow}><button className={s.btnSecondary} onClick={()=>{setErro('');setStep(3);}}>← Voltar</button><button className={s.btnPrimary} disabled={salvando} onClick={salvar}>{salvando?'⏳ Salvando...':'✓ Salvar Concretagem'}</button></div>
            </div>
          )}
        </div>
      )}
    </Modal>
  );
}

// ════════════════════════════════════════════════
// MODAL: LANÇAR / EDITAR BT
// ════════════════════════════════════════════════
function ModalLancarBT({ open, onClose, pecas, concretagens, pecaConc, btsConfig, lancamentos, onSalvo }) {
  const [modoLancamento, setModoLancamento] = useState('menu'); // menu | nova | editar
  const [step,setStep]=useState(1);
  const [concId,setConcId]=useState('');
  const [filtroTipoBT,setFiltroTipoBT]=useState('todos');
  const [btId,setBtId]=useState('');
  const [nfEdit,setNfEdit]=useState('');
  const [codEdit,setCodEdit]=useState('');
  const [hora,setHora]=useState('');
  const [linhas,setLinhas]=useState([{pecaId:'',pct:''}]);
  const [sobra,setSobra]=useState('');
  const [perda,setPerda]=useState('');
  const [salvando,setSalvando]=useState(false);
  const [erro,setErro]=useState('');

  useEffect(()=>{
    if(!open) return;
    setModoLancamento('menu');setErro('');setConcId('');setBtId('');setStep(1);
    setLinhas([{pecaId:'',pct:''}]);setSobra('');setPerda('');setFiltroTipoBT('todos');
    const now=new Date();
    setHora(`${String(now.getHours()).padStart(2,'0')}:${String(now.getMinutes()).padStart(2,'0')}`);
  },[open]);

  const btsConc=btsConfig.filter(b=>b.concretagemId===concId).sort((a,b)=>a.numero-b.numero);
  const btSel=btsConc.find(b=>b.id===btId);
  const lancamentosbt=lancamentos.filter(l=>l.btConfigId===btId);

  useEffect(()=>{
    if(btSel){setNfEdit(btSel.notaFiscal||'');setCodEdit(btSel.codigoBT||'');}
  },[btId]);

  // Ao abrir edição de uma BT já lançada, pré-preenche as linhas
  function iniciarEdicao(){
    if(!btId) return;
    if(lancamentosbt.length===0){setErro('Esta BT ainda não foi lançada');return;}
    setErro('');
    // Pré-preenche linhas com os dados existentes
    const ls = lancamentosbt.map(l => {
      const peca = pecas.find(p=>p.id===l.pecaId);
      const pct  = peca&&peca.volume>0 ? (l.volume/peca.volume*100).toFixed(2) : '';
      return { pecaId:l.pecaId, pct };
    });
    setLinhas(ls.length?ls:[{pecaId:'',pct:''}]);
    setSobra(String(lancamentosbt[0]?.sobraCaminhao||''));
    setPerda(String(lancamentosbt[0]?.perdaObra||''));
    setModoLancamento('editar');
    setStep(2);
  }

  const pecasConc=useMemo(()=>{
    if(!concId) return [];
    const ids=pecaConc.filter(pc=>pc.concretagemId===concId).map(pc=>pc.pecaId);
    return pecas.filter(p=>ids.includes(p.id));
  },[concId,pecaConc,pecas]);

  const volLinha=l=>{const p=pecas.find(x=>x.id===l.pecaId);const pct=parseFloat(l.pct);return p&&!isNaN(pct)?(pct/100)*p.volume:0;};
  const totalUsado=linhas.reduce((s,l)=>s+volLinha(l),0);
  const volPrevisto=btSel?.volumePrevisto||0;
  const sobEstimada=Math.max(0,volPrevisto-totalUsado);
  const perdaCaminhao=btSel?volPrevisto-totalUsado:0;

  const addLinha=()=>setLinhas(p=>[...p,{pecaId:'',pct:''}]);
  const remLinha=i=>setLinhas(p=>p.filter((_,idx)=>idx!==i));
  const updLinha=(i,f,v)=>setLinhas(p=>p.map((l,idx)=>idx===i?{...l,[f]:v}:l));

  async function salvar(){
    setErro('');
    const linhasVal=linhas.filter(l=>l.pecaId&&parseFloat(l.pct)>0);
    if(!concId||!btId){setErro('Selecione concretagem e BT');return;}
    setSalvando(true);
    try{
      await apiLancarBT({btConfigId:btId,concretagemId:concId,linhas:linhasVal,
        sobraCaminhao:parseFloat(sobra)||sobEstimada,perdaObra:parseFloat(perda)||0,
        hora,pecas,notaFiscal:nfEdit,codigoBT:codEdit});
      onSalvo(modoLancamento==='editar'?`✓ BT-${btSel?.numero} atualizada!`:`✓ BT-${btSel?.numero} lançada!`);
      onClose();
    }catch(e){setErro('Erro: '+e.message);}finally{setSalvando(false);}
  }

  if(!open) return null;
  return(
    <div className={s.modalOverlay} onClick={e=>e.target===e.currentTarget&&onClose()}>
      <div className={`${s.modal} ${s.modalWide}`}>
        <div className={s.modalTitle}>⊕ Betonada (BT)</div>

        {/* Menu nova vs editar */}
        {modoLancamento==='menu'&&step===1&&(
          <div>
            <div className={s.formGroup} style={{marginBottom:20}}>
              <label className={s.formLabel}>Concretagem</label>
              <select className={s.formSelect} value={concId} onChange={e=>{setConcId(e.target.value);setBtId('');}}>
                <option value="">— selecione —</option>
                {[...concretagens].sort((a,b)=>a.numero-b.numero).map(c=><option key={c.id} value={c.id}>Nº {c.numero} — {c.data}{c.descricao?` | ${c.descricao}`:''}</option>)}
              </select>
            </div>
            {concId&&(
              <div>
                <label className={s.formLabel} style={{display:'block',marginBottom:12}}>Selecione a BT</label>
                {btsConc.length===0
                  ?<div className={s.empty}>Nenhuma BT configurada. Configure em "Concretagens".</div>
                  :<div style={{display:'flex',flexWrap:'wrap',gap:10,marginBottom:16}}>
                    {btsConc.map(b=>{
                      const jafoi=lancamentos.some(l=>l.btConfigId===b.id);
                      const sel=b.id===btId;
                      return(
                        <div key={b.id} style={{display:'flex',flexDirection:'column',gap:0}}>
                          <div onClick={()=>setBtId(b.id)} style={{padding:'16px 20px',border:`2px solid ${sel?'var(--accent)':jafoi?'var(--green)':'var(--border)'}`,background:sel?'rgba(232,162,37,0.1)':jafoi?'rgba(62,207,122,0.05)':'transparent',cursor:'pointer',minWidth:110,transition:'all 0.15s'}}>
                            <div style={{fontFamily:'var(--mono)',fontSize:22,color:sel?'var(--accent)':jafoi?'var(--green)':'var(--text2)',fontWeight:700}}>BT-{b.numero}</div>
                            <div style={{fontFamily:'var(--mono)',fontSize:13,color:'var(--text3)',marginTop:4}}>{fmt4(b.volumePrevisto)} m³</div>
                            {b.notaFiscal&&<div style={{fontFamily:'var(--mono)',fontSize:11,color:'var(--text3)'}}>NF:{b.notaFiscal}</div>}
                            {jafoi&&<div style={{fontFamily:'var(--mono)',fontSize:12,color:'var(--green)',marginTop:4}}>✓ Lançada</div>}
                          </div>
                          {jafoi&&sel&&(
                            <button onClick={e=>{e.stopPropagation();iniciarEdicao();}}
                              style={{background:'var(--surface2)',border:'2px solid var(--accent)',borderTop:'none',color:'var(--accent)',fontFamily:'var(--cond)',fontWeight:700,fontSize:13,letterSpacing:1,padding:'10px',cursor:'pointer',textTransform:'uppercase',width:'100%'}}>
                              ✎ Editar BT
                            </button>
                          )}
                        </div>
                      );
                    })}
                  </div>
                }
                {btId&&!lancamentos.some(l=>l.btConfigId===btId)&&(
                  <div style={{marginTop:4,display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:12}}>
                    <div className={s.formGroup}><label className={s.formLabel}>Hora</label><input className={s.formInput} type="time" value={hora} onChange={e=>setHora(e.target.value)}/></div>
                    <div className={s.formGroup}><label className={s.formLabel}>Nota Fiscal</label><input className={s.formInput} placeholder="NF" value={nfEdit} onChange={e=>setNfEdit(e.target.value)}/></div>
                    <div className={s.formGroup}><label className={s.formLabel}>Código BT</label><input className={s.formInput} placeholder="Código" value={codEdit} onChange={e=>setCodEdit(e.target.value)}/></div>
                  </div>
                )}
              </div>
            )}
            <div className={s.btnRow}>
              <button className={s.btnSecondary} onClick={onClose}>Cancelar</button>
              {btId&&!lancamentos.some(l=>l.btConfigId===btId)&&(
                <button className={s.btnPrimary} onClick={()=>{if(!concId||!btId){setErro('Selecione concretagem e BT');return;}setErro('');setModoLancamento('nova');setStep(2);}}>Próximo →</button>
              )}
            </div>
          </div>
        )}

        {false&&(
          <div>
            <div className={s.formGroup} style={{marginBottom:16}}>
              <label className={s.formLabel}>Concretagem</label>
              <select className={s.formSelect} value={concId} onChange={e=>{setConcId(e.target.value);setBtId('');}}>
                <option value="">— selecione —</option>
                {[...concretagens].sort((a,b)=>a.numero-b.numero).map(c=><option key={c.id} value={c.id}>Nº {c.numero} — {c.data}{c.descricao?` | ${c.descricao}`:''}</option>)}
              </select>
            </div>
            {concId&&(
              <div>
                <label className={s.formLabel} style={{display:'block',marginBottom:10}}>BTs lançadas</label>
                <div style={{display:'flex',flexWrap:'wrap',gap:10,marginBottom:16}}>
                  {btsConc.filter(b=>lancamentos.some(l=>l.btConfigId===b.id)).map(b=>(
                    <div key={b.id} onClick={()=>setBtId(b.id)} style={{padding:'14px 18px',border:`2px solid ${b.id===btId?'var(--accent)':'var(--green)'}`,background:b.id===btId?'rgba(232,162,37,0.1)':'transparent',cursor:'pointer',minWidth:100}}>
                      <div style={{fontFamily:'var(--mono)',fontSize:20,color:b.id===btId?'var(--accent)':'var(--green)',fontWeight:700}}>BT-{b.numero}</div>
                      <div style={{fontFamily:'var(--mono)',fontSize:12,color:'var(--text3)',marginTop:4}}>{fmt4(b.volumePrevisto)} m³</div>
                    </div>
                  ))}
                  {btsConc.filter(b=>lancamentos.some(l=>l.btConfigId===b.id)).length===0&&<div className={s.empty}>Nenhuma BT lançada nesta concretagem</div>}
                </div>
              </div>
            )}
            {erro&&<div className={s.alertRed} style={{marginBottom:12}}>{erro}</div>}
            <div className={s.btnRow}>
              <button className={s.btnSecondary} onClick={()=>setModoLancamento('menu')}>← Voltar</button>
              <button className={s.btnPrimary} onClick={iniciarEdicao}>Editar BT selecionada →</button>
            </div>
          </div>
        )}

        {/* Fluxo nova / editar — steps */}
        {(modoLancamento==='nova'||modoLancamento==='editar')&&(
          <div>
            <div className={s.steps}>
              {['Selecionar BT','Peças & %','Fechamento'].map((label,i)=>(
                <div key={i} className={`${s.step} ${step===i+1?s.stepActive:step>i+1?s.stepDone:''}`}>
                  <div className={s.stepNum}>{step>i+1?'✓':i+1}</div><div className={s.stepLabel}>{label}</div>
                </div>
              ))}
            </div>
            {modoLancamento==='editar'&&<div className={s.alertBlue} style={{marginBottom:14}}>✎ Modo edição — os lançamentos existentes serão substituídos.</div>}
            {erro&&<div className={s.alertRed} style={{marginBottom:14}}>{erro}</div>}

            {step===1&&(
              <div>
                <div className={s.formGroup} style={{marginBottom:16}}>
                  <label className={s.formLabel}>Concretagem</label>
                  <select className={s.formSelect} value={concId} onChange={e=>{setConcId(e.target.value);setBtId('');}}>
                    <option value="">— selecione —</option>
                    {[...concretagens].sort((a,b)=>a.numero-b.numero).map(c=><option key={c.id} value={c.id}>Nº {c.numero} — {c.data}{c.descricao?` | ${c.descricao}`:''}</option>)}
                  </select>
                </div>
                {concId&&(
                  <div>
                    <label className={s.formLabel} style={{display:'block',marginBottom:10}}>Selecione a BT</label>
                    {btsConc.length===0?<div className={s.empty}>Nenhuma BT configurada. Configure em "Concretagens".</div>
                      :<div style={{display:'flex',flexWrap:'wrap',gap:10}}>
                        {btsConc.map(b=>{const jafoi=lancamentos.some(l=>l.btConfigId===b.id);const sel=b.id===btId;return(
                          <div key={b.id} style={{display:'flex',flexDirection:'column',gap:0}}>
                            <div onClick={()=>setBtId(b.id)} style={{padding:'14px 18px',border:`2px solid ${sel?'var(--accent)':jafoi?'var(--green)':'var(--border)'}`,background:sel?'rgba(232,162,37,0.1)':jafoi?'rgba(62,207,122,0.05)':'transparent',cursor:'pointer',minWidth:110,transition:'all 0.15s'}}>
                              <div style={{fontFamily:'var(--mono)',fontSize:22,color:sel?'var(--accent)':jafoi?'var(--green)':'var(--text2)',fontWeight:700}}>BT-{b.numero}</div>
                              <div style={{fontFamily:'var(--mono)',fontSize:13,color:'var(--text3)',marginTop:4}}>{fmt4(b.volumePrevisto)} m³</div>
                              {b.notaFiscal&&<div style={{fontFamily:'var(--mono)',fontSize:11,color:'var(--text3)'}}>NF:{b.notaFiscal}</div>}
                              {jafoi&&<div style={{fontFamily:'var(--mono)',fontSize:12,color:'var(--green)',marginTop:4}}>✓ Lançada</div>}
                            </div>
                            {jafoi&&sel&&(
                              <button onClick={e=>{e.stopPropagation();iniciarEdicao();}}
                                style={{background:'var(--surface2)',border:'1px solid var(--accent)',borderTop:'none',color:'var(--accent)',fontFamily:'var(--cond)',fontWeight:700,fontSize:12,letterSpacing:1,padding:'8px',cursor:'pointer',textTransform:'uppercase',transition:'all 0.15s'}}
                                onMouseOver={e=>e.target.style.background='rgba(232,162,37,0.15)'}
                                onMouseOut={e=>e.target.style.background='var(--surface2)'}>
                                ✎ Editar BT
                              </button>
                            )}
                          </div>
                        );})}
                      </div>
                    }
                    {btId&&<div style={{marginTop:16,display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:12}}>
                      <div className={s.formGroup}><label className={s.formLabel}>Hora</label><input className={s.formInput} type="time" value={hora} onChange={e=>setHora(e.target.value)}/></div>
                      <div className={s.formGroup}><label className={s.formLabel}>Nota Fiscal</label><input className={s.formInput} placeholder="NF" value={nfEdit} onChange={e=>setNfEdit(e.target.value)}/></div>
                      <div className={s.formGroup}><label className={s.formLabel}>Código BT</label><input className={s.formInput} placeholder="Código" value={codEdit} onChange={e=>setCodEdit(e.target.value)}/></div>
                    </div>}
                  </div>
                )}
                <div className={s.btnRow}>
                  <button className={s.btnSecondary} onClick={()=>{setModoLancamento('menu');setStep(1);}}>← Voltar</button>
                  <button className={s.btnPrimary} onClick={()=>{if(!concId||!btId){setErro('Selecione concretagem e BT');return;}setErro('');setStep(2);}}>Próximo →</button>
                </div>
              </div>
            )}

            {step===2&&(
              <div>
                {/* Filtro por tipo de peça */}
                {(()=>{
                  const ORDEM_T=['todos','Pilar','Viga','Laje','Escada','Rampa','Fundação','Cortina','Outro'];
                  const lista = pecasConc.length>0?pecasConc:pecas;
                  const tiposDisp=['todos',...ORDEM_T.filter(t=>t!=='todos'&&lista.some(p=>p.tipo===t)),
                    ...lista.map(p=>p.tipo).filter(t=>!ORDEM_T.includes(t)).filter((t,i,a)=>a.indexOf(t)===i)];
                  if(tiposDisp.length<=1) return null;
                  return(
                    <div style={{display:'flex',gap:6,marginBottom:12,flexWrap:'wrap',paddingBottom:10,borderBottom:'1px solid var(--border)'}}>
                      <span style={{fontSize:11,color:'var(--text3)',alignSelf:'center',marginRight:4,fontWeight:600,textTransform:'uppercase',letterSpacing:1}}>Tipo:</span>
                      {tiposDisp.map(t=>(
                        <button key={t} onClick={()=>setFiltroTipoBT(t)} style={{
                          padding:'5px 14px',borderRadius:20,border:'1px solid',fontSize:12,fontWeight:600,cursor:'pointer',transition:'all 0.15s',
                          background:filtroTipoBT===t?'var(--accent)':'transparent',
                          color:filtroTipoBT===t?'#111':'var(--text3)',
                          borderColor:filtroTipoBT===t?'var(--accent)':'var(--border)',
                        }}>{t==='todos'?'Todos':t}</button>
                      ))}
                    </div>
                  );
                })()}

                <div className={s.btResumo}>
                  <span style={{color:'var(--accent)',fontWeight:700}}>BT-{btSel?.numero}</span><span>|</span>
                  <span>{fmt4(volPrevisto)} m³ previsto</span><span>|</span>
                  <span style={{color:totalUsado>volPrevisto?'var(--blue)':'var(--green)',fontWeight:700}}>{fmt4(totalUsado)} m³ lançado</span><span>|</span>
                  <span style={{color:perdaCaminhao>0?'var(--red)':perdaCaminhao<0?'var(--blue)':'var(--text3)'}}>
                    {perdaCaminhao>0?`▼ perda ${fmt4(perdaCaminhao)} m³`:perdaCaminhao<0?`▲ sobra +${fmt4(Math.abs(perdaCaminhao))} m³`:'—'}
                  </span>
                </div>
                {linhas.map((l,i)=>{const vol=volLinha(l);return(
                  <div key={i} className={s.pecaLinha}>
                    <div className={s.formGroup} style={{flex:2}}>
                      {i===0&&<label className={s.formLabel}>Peça{pecasConc.length>0?' (desta concretagem)':''}</label>}
                      <select className={s.formSelect} value={l.pecaId} onChange={e=>updLinha(i,'pecaId',e.target.value)}>
                        <option value="">— selecione —</option>
                        {(pecasConc.length>0?pecasConc:pecas).filter(p=>filtroTipoBT==='todos'||p.tipo===filtroTipoBT).sort((a,b)=>a.nome.localeCompare(b.nome)).map(p=><option key={p.id} value={p.id}>{p.nome} ({p.andar}) — {fmt4(p.volume)} m³</option>)}
                      </select>
                    </div>
                    <div className={s.formGroup} style={{width:100}}>
                      {i===0&&<label className={s.formLabel}>% nesta BT</label>}
                      <input className={s.formInput} type="number" min="0.01" max="100" step="0.5" placeholder="%" value={l.pct} onChange={e=>updLinha(i,'pct',e.target.value)}/>
                    </div>
                    <div className={s.formGroup} style={{width:100}}>
                      {i===0&&<label className={s.formLabel}>m³</label>}
                      <input className={s.formInput} readOnly value={vol>0?fmt4(vol):''} style={{color:'var(--accent)'}}/>
                    </div>
                    <div style={{alignSelf:'flex-end',paddingBottom:2}}>{linhas.length>1&&<button className={s.btnDanger} onClick={()=>remLinha(i)}>✕</button>}</div>
                  </div>
                );})}
                <div style={{display:'flex',gap:10,marginTop:12}}>
                  <button className={s.btnSecondary} onClick={addLinha}>+ Adicionar peça</button>
                  <button onClick={()=>setLinhas([{pecaId:'',pct:''}])} style={{background:'none',border:'1px solid var(--red)',color:'var(--red)',padding:'8px 14px',borderRadius:'var(--radius-sm)',fontSize:12,fontWeight:600,cursor:'pointer'}}>
                    🗑 Zerar tudo
                  </button>
                </div>
                {totalUsado>volPrevisto&&<div className={s.alertBlue} style={{marginTop:10}}>ℹ Volume acima do previsto — sobra inesperada de {fmt4(totalUsado-volPrevisto)} m³.</div>}
                <div className={s.btnRow}>
                  <button className={s.btnSecondary} onClick={()=>setStep(1)}>← Voltar</button>
                  <button className={s.btnPrimary} onClick={()=>{setErro('');setStep(3);}}>Próximo →</button>
                </div>
              </div>
            )}

            {step===3&&(
              <div>
                <div className={s.btResumo} style={{marginBottom:16}}>
                  <span style={{color:'var(--accent)',fontWeight:700}}>BT-{btSel?.numero}</span><span>|</span>
                  <span>{fmt4(volPrevisto)} m³ previsto</span><span>|</span>
                  <span style={{color:'var(--green)',fontWeight:700}}>{fmt4(totalUsado)} m³ executado</span><span>|</span>
                  <span style={{color:perdaCaminhao>0?'var(--red)':perdaCaminhao<0?'var(--blue)':'var(--text3)'}}>
                    {perdaCaminhao>0?`perda caminhão: ${fmt4(perdaCaminhao)} m³`:perdaCaminhao<0?`sobra inesperada: +${fmt4(Math.abs(perdaCaminhao))} m³`:'sem perda caminhão'}
                  </span>
                </div>
                {linhas.filter(l=>l.pecaId&&parseFloat(l.pct)>0).map((l,i)=>{const p=pecas.find(x=>x.id===l.pecaId);return<div key={i} style={{display:'flex',justifyContent:'space-between',padding:'8px 0',borderBottom:'1px solid var(--border)',fontFamily:'var(--mono)',fontSize:13}}><span style={{color:'var(--text)'}}>{p?p.nome:l.pecaId}</span><span style={{color:'var(--accent)',fontWeight:700}}>{l.pct}% → {fmt4(volLinha(l))} m³</span></div>;})}
                <div className={s.formGrid} style={{marginTop:18}}>
                  <div className={s.formGroup}><label className={s.formLabel}>Sobra que foi embora (m³)</label><input className={s.formInput} type="number" step="0.0001" min="0" placeholder={`sugestão: ${fmt4(sobEstimada)}`} value={sobra} onChange={e=>setSobra(e.target.value)}/></div>
                  <div className={s.formGroup}><label className={s.formLabel}>Perda em obra (m³)</label><input className={s.formInput} type="number" step="0.0001" min="0" placeholder="0.0000" value={perda} onChange={e=>setPerda(e.target.value)}/></div>
                </div>
                <div className={s.btnRow}>
                  <button className={s.btnSecondary} onClick={()=>setStep(2)}>← Voltar</button>
                  <button className={s.btnPrimary} disabled={salvando} onClick={salvar}>{salvando?'⏳ Salvando...':(modoLancamento==='editar'?'✓ Atualizar BT':'✓ Confirmar BT')}</button>
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}


// ════════════════════════════════════════════════
// FILTRO BAR — Cards com dropdown vertical
// ════════════════════════════════════════════════
function FiltroBar({ andares, concretagens, pecaConc, pecas, filtroAndar, setFiltroAndar, filtroConc, setFiltroConc }) {
  const [aberto, setAberto] = useState(null);

  const labelAndar = filtroAndar === 'todos' ? 'Todos os Andares' : filtroAndar;
  const concSel = concretagens.find(c=>c.id===filtroConc);
  const labelConc = filtroConc === 'todas' ? 'Todas as Concretagens'
    : `Concretagem Nº${concSel?.numero} — ${concSel?.data||''}`;

  // Filtrar concretagens pelo andar selecionado
  const concDisp = filtroAndar === 'todos' ? concretagens : concretagens.filter(c => {
    const pecaIds = pecaConc.filter(pc=>pc.concretagemId===c.id).map(pc=>pc.pecaId);
    return pecas.filter(p=>pecaIds.includes(p.id)).some(p=>p.andar===filtroAndar);
  });

  function toggle(tipo) { setAberto(prev => prev===tipo ? null : tipo); }
  function selAndar(val) {
    setFiltroAndar(val);
    setFiltroConc('todas'); // reset concretagem ao mudar andar
    setAberto(null);
  }
  function selConc(val) { setFiltroConc(val); setAberto(null); }

  return (
    <div className={s.filtroBar} style={{marginBottom:20}}>
      {aberto&&<div onClick={()=>setAberto(null)} style={{position:'fixed',inset:0,zIndex:199}}/>}

      {/* Card Andar */}
      <div className={`${s.filtroCard} ${aberto==='andar'?s.filtroCardActive:''}`} onClick={()=>toggle('andar')}>
        <div className={s.filtroCardLeft}>
          <span className={s.filtroCardLabel}>Andar</span>
          <span className={`${s.filtroCardValue} ${filtroAndar!=='todos'?s.filtroCardValueActive:''}`}>{labelAndar}</span>
        </div>
        <span className={`${s.filtroChevron} ${aberto==='andar'?s.filtroChevronOpen:''}`}>▼</span>
        {aberto==='andar'&&(
          <div className={s.filtroDropdown} onClick={e=>e.stopPropagation()}>
            {['todos',...andares].map(a=>(
              <button key={a} className={`${s.filtroOption} ${filtroAndar===a?s.filtroOptionActive:''}`} onClick={()=>selAndar(a)}>
                {a==='todos'?'Todos os Andares':a}
                {filtroAndar===a&&<span>✓</span>}
              </button>
            ))}
          </div>
        )}
      </div>

      {/* Card Concretagem */}
      <div className={`${s.filtroCard} ${aberto==='concretagem'?s.filtroCardActive:''}`} onClick={()=>toggle('concretagem')}>
        <div className={s.filtroCardLeft}>
          <span className={s.filtroCardLabel}>Concretagem</span>
          <span className={`${s.filtroCardValue} ${filtroConc!=='todas'?s.filtroCardValueActive:''}`}>{labelConc}</span>
        </div>
        <span className={`${s.filtroChevron} ${aberto==='concretagem'?s.filtroChevronOpen:''}`}>▼</span>
        {aberto==='concretagem'&&(
          <div className={s.filtroDropdown} onClick={e=>e.stopPropagation()}>
            {['todas',...[...concDisp].sort((a,b)=>a.numero-b.numero)].map(c=>{
              const id=typeof c==='string'?c:c.id;
              const label=typeof c==='string'?'Todas as Concretagens':`Nº${c.numero} — ${c.data}${c.descricao?' | '+c.descricao:''}`;
              return(
                <button key={id} className={`${s.filtroOption} ${filtroConc===id?s.filtroOptionActive:''}`} onClick={()=>selConc(id)}>
                  {label}
                  {filtroConc===id&&<span>✓</span>}
                </button>
              );
            })}
            {concDisp.length===0&&<div style={{padding:'16px',color:'var(--text3)',fontSize:13,textAlign:'center'}}>Nenhuma concretagem para este andar</div>}
          </div>
        )}
      </div>
    </div>
  );
}




// ════════════════════════════════════════════════
// CALCULAR CONCRETO — Escada e Pilar
// ════════════════════════════════════════════════

const TIPOS_PILAR = [
  { id:'ret',  label:'Retangular', desc:'A × B',      img:'▬', formula:'(PD × A × B) / 1.000.000' },
  { id:'red',  label:'Redondo',    desc:'Ø A',         img:'●', formula:'(π × A² / 4 × PD) / 1.000.000' },
  { id:'l',    label:'Tipo L',     desc:'A,B,C,D',     img:'⌐', formula:'(A×(B−D) + C×D) × PD / 1.000.000' },
  { id:'t',    label:'Tipo T',     desc:'A,B,C,D',     img:'⊤', formula:'(A×B + C×D) × PD / 1.000.000' },
];

function calcVolPilar(tipo, pd, a, b, c, d) {
  const P=parseFloat(pd)||0, A=parseFloat(a)||0, B=parseFloat(b)||0,
        C=parseFloat(c)||0, D=parseFloat(d)||0;
  if(tipo==='ret') return (P*A*B)/1e6;
  if(tipo==='red') return ((Math.PI*A*A/4)*P)/1e6;
  if(tipo==='l')   return ((A*(B-D))+(C*D))*P/1e6;
  if(tipo==='t')   return ((A*B)+(C*D))*P/1e6;
  return 0;
}

function calcVolEscada(comp, larg, alt) {
  return (parseFloat(comp)||0)*(parseFloat(larg)||0)*(parseFloat(alt)||0)/1e6;
}

function PilarDiagram({ tipo }) {
  const sz = 120;
  if(tipo==='ret') return(
    <svg width={sz} height={sz} style={{margin:'0 auto',display:'block'}}>
      <rect x={20} y={20} width={80} height={80} fill="rgba(245,197,24,0.15)" stroke="var(--accent)" strokeWidth={2} rx={2}/>
      <line x1={20} y1={60} x2={10} y2={60} stroke="var(--blue)" strokeWidth={1.5}/>
      <text x={5} y={55} fontSize={9} fill="var(--blue)" textAnchor="middle">B</text>
      <line x1={60} y1={20} x2={60} y2={10} stroke="var(--blue)" strokeWidth={1.5}/>
      <text x={60} y={7} fontSize={9} fill="var(--blue)" textAnchor="middle">A</text>
      <text x={60} y={65} fontSize={11} fill="var(--text2)" textAnchor="middle">Retangular</text>
    </svg>
  );
  if(tipo==='red') return(
    <svg width={sz} height={sz} style={{margin:'0 auto',display:'block'}}>
      <circle cx={60} cy={55} r={40} fill="rgba(245,197,24,0.15)" stroke="var(--accent)" strokeWidth={2}/>
      <line x1={60} y1={55} x2={100} y2={55} stroke="var(--blue)" strokeWidth={1.5}/>
      <text x={82} y={50} fontSize={9} fill="var(--blue)">A</text>
      <text x={60} y={115} fontSize={10} fill="var(--text2)" textAnchor="middle">Redondo (Ø)</text>
    </svg>
  );
  if(tipo==='l') return(
    <svg width={sz} height={sz} style={{margin:'0 auto',display:'block'}}>
      <path d="M20,20 L20,100 L55,100 L55,70 L50,70 L50,20 Z" fill="rgba(245,197,24,0.15)" stroke="var(--accent)" strokeWidth={2}/>
      <text x={35} y={45} fontSize={9} fill="var(--blue)" textAnchor="middle">A</text>
      <text x={22} y={85} fontSize={9} fill="var(--blue)">C</text>
      <text x={38} y={108} fontSize={9} fill="var(--blue)" textAnchor="middle">D</text>
      <text x={52} y={50} fontSize={9} fill="var(--blue)">B</text>
      <text x={40} y={118} fontSize={10} fill="var(--text2)" textAnchor="middle">Tipo L</text>
    </svg>
  );
  if(tipo==='t') return(
    <svg width={sz} height={sz} style={{margin:'0 auto',display:'block'}}>
      <path d="M10,20 L110,20 L110,45 L70,45 L70,100 L50,100 L50,45 L10,45 Z" fill="rgba(245,197,24,0.15)" stroke="var(--accent)" strokeWidth={2}/>
      <text x={60} y={35} fontSize={9} fill="var(--blue)" textAnchor="middle">A</text>
      <text x={5} y={35} fontSize={9} fill="var(--blue)">B</text>
      <text x={60} y={75} fontSize={9} fill="var(--blue)" textAnchor="middle">C</text>
      <text x={72} y={75} fontSize={9} fill="var(--blue)">D</text>
      <text x={60} y={115} fontSize={10} fill="var(--text2)" textAnchor="middle">Tipo T</text>
    </svg>
  );
  return null;
}

// Armazenamento local do levantamento
const STORAGE_KEY = 'concreto_levantamento';
function getLevantamento() { try{return JSON.parse(localStorage.getItem(STORAGE_KEY)||'[]');}catch{return[];} }
function setLevantamento(items) { try{localStorage.setItem(STORAGE_KEY,JSON.stringify(items));}catch{} }

function PageCalcularConcreto({ andares, onRefresh }) {
  const [tipoFeature, setTipoFeature] = useState(null); // null | 'pilar' | 'escada'
  const [tipoPilar, setTipoPilar]     = useState('ret');
  const [form, setForm]               = useState({});
  const [vol, setVol]                 = useState(null);
  const [saved, setSaved]             = useState(false);
  const andaresList                   = andares.length ? andares : [];

  function upd(k,v) { setForm(p=>({...p,[k]:v})); setSaved(false); setVol(null); }

  function calcular() {
    let v = 0;
    if(tipoFeature==='pilar')
      v = calcVolPilar(tipoPilar, form.pd, form.a, form.b, form.c, form.d);
    if(tipoFeature==='escada')
      v = calcVolEscada(form.comp, form.larg, form.alt);
    setVol(v);
    setSaved(false);
  }

  function adicionar() {
    if(!vol||!form.nome) return;
    const item = {
      id: `lev_${Date.now()}`,
      nome: form.nome,
      tipo: tipoFeature==='pilar'?'Pilar':'Escada',
      andar: form.andar||'',
      volume: parseFloat(vol.toFixed(6)),
      detalhes: tipoFeature==='pilar'
        ? `${TIPOS_PILAR.find(t=>t.id===tipoPilar)?.label} PD=${form.pd} A=${form.a}${form.b?` B=${form.b}`:''}${form.c?` C=${form.c}`:''}${form.d?` D=${form.d}`:''}`
        : `L=${form.comp} × W=${form.larg} × H=${form.alt}`,
    };
    const lista = [...getLevantamento(), item];
    setLevantamento(lista);
    setSaved(true);
    setForm({andar:form.andar||''});
    setVol(null);
  }

  return(
    <div className={s.page} style={{animation:'fadein 0.25s ease'}}>
      <div style={{marginBottom:24}}>
        <h2 style={{fontSize:22,fontWeight:800,color:'var(--text)',marginBottom:4}}>📐 Calcular Concreto</h2>
        <p style={{color:'var(--text3)',fontSize:13}}>Calcule o volume de cada peça e adicione ao levantamento.</p>
      </div>

      {/* Seleção de tipo */}
      {!tipoFeature&&(
        <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(160px,1fr))',gap:12,maxWidth:600}}>
          {[
            {id:'pilar',  icon:'⬛', label:'Pilar',   sub:'Ret, Redondo, L, T'},
            {id:'rampa',   icon:'⟋',  label:'Rampa',   sub:'Comprimento × Largura × Esp. Laje'},
            {id:'escada',  icon:'🪜',  label:'Escada',  sub:'Patamares + Degraus (pisada × espelho × largura)'},
          ].map(t=>(
            <div key={t.id} className={s.menuCard} onClick={()=>setTipoFeature(t.id)} style={{textAlign:'center',padding:'28px 16px'}}>
              <div style={{fontSize:36,marginBottom:10}}>{t.icon}</div>
              <div className={s.menuCardTitle}>{t.label}</div>
              <div className={s.menuCardSub}>{t.sub}</div>
            </div>
          ))}
        </div>
      )}

      {/* FORMULÁRIO PILAR */}
      {tipoFeature==='pilar'&&(
        <div style={{maxWidth:680}}>
          <button className={s.btnSecondary} style={{marginBottom:20}} onClick={()=>{setTipoFeature(null);setVol(null);setForm({});}}>← Voltar</button>

          {/* Seletor tipo de pilar */}
          <div style={{marginBottom:20}}>
            <label className={s.formLabel} style={{display:'block',marginBottom:10}}>Tipo de Pilar</label>
            <div style={{display:'grid',gridTemplateColumns:'repeat(4,1fr)',gap:10}}>
              {TIPOS_PILAR.map(t=>(
                <div key={t.id} onClick={()=>setTipoPilar(t.id)}
                  style={{padding:'14px 10px',border:`2px solid ${tipoPilar===t.id?'var(--accent)':'var(--border)'}`,borderRadius:'var(--radius-sm)',
                    background:tipoPilar===t.id?'rgba(245,197,24,0.08)':'var(--surface2)',cursor:'pointer',textAlign:'center',transition:'all 0.15s'}}>
                  <div style={{fontSize:24,marginBottom:6}}>{t.img}</div>
                  <div style={{fontWeight:700,fontSize:13,color:tipoPilar===t.id?'var(--accent)':'var(--text)'}}>{t.label}</div>
                  <div style={{fontSize:10,color:'var(--text3)',marginTop:2}}>{t.desc}</div>
                </div>
              ))}
            </div>
          </div>

          <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:20,alignItems:'start'}}>
            {/* Diagrama */}
            <div className={s.panel} style={{padding:20}}>
              <div className={s.panelTitle} style={{marginBottom:16}}>Diagrama</div>
              <PilarDiagram tipo={tipoPilar}/>
              <div style={{marginTop:12,fontFamily:'var(--mono)',fontSize:11,color:'var(--text3)',textAlign:'center',lineHeight:1.8}}>
                {TIPOS_PILAR.find(t=>t.id===tipoPilar)?.formula}
              </div>
            </div>

            {/* Campos */}
            <div>
              <div className={s.formGrid} style={{marginBottom:14}}>
                <div className={s.formGroup}>
                  <label className={s.formLabel}>Andar</label>
                  <input className={s.formInput} list="andares-list" placeholder="ex: Térreo" value={form.andar||''} onChange={e=>upd('andar',e.target.value)}/>
                  <datalist id="andares-list">{andaresList.map(a=><option key={a} value={a}/>)}</datalist>
                </div>
                <div className={s.formGroup}>
                  <label className={s.formLabel}>Nome da Peça</label>
                  <input className={s.formInput} placeholder="ex: P-01" value={form.nome||''} onChange={e=>upd('nome',e.target.value)}/>
                </div>
                <div className={s.formGroup}>
                  <label className={s.formLabel}>Pé Direito [cm]</label>
                  <input className={s.formInput} type="number" step="0.1" min="0" value={form.pd||''} onChange={e=>upd('pd',e.target.value)}/>
                </div>
                {(tipoPilar==='ret'||tipoPilar==='red'||tipoPilar==='l'||tipoPilar==='t')&&(
                  <div className={s.formGroup}>
                    <label className={s.formLabel}>Medida A [cm]{tipoPilar==='red'?' (Diâmetro)':''}</label>
                    <input className={s.formInput} type="number" step="0.1" min="0" value={form.a||''} onChange={e=>upd('a',e.target.value)}/>
                  </div>
                )}
                {(tipoPilar==='ret'||tipoPilar==='l'||tipoPilar==='t')&&(
                  <div className={s.formGroup}>
                    <label className={s.formLabel}>Medida B [cm]</label>
                    <input className={s.formInput} type="number" step="0.1" min="0" value={form.b||''} onChange={e=>upd('b',e.target.value)}/>
                  </div>
                )}
                {(tipoPilar==='l'||tipoPilar==='t')&&(<>
                  <div className={s.formGroup}>
                    <label className={s.formLabel}>Medida C [cm]</label>
                    <input className={s.formInput} type="number" step="0.1" min="0" value={form.c||''} onChange={e=>upd('c',e.target.value)}/>
                  </div>
                  <div className={s.formGroup}>
                    <label className={s.formLabel}>Medida D [cm]</label>
                    <input className={s.formInput} type="number" step="0.1" min="0" value={form.d||''} onChange={e=>upd('d',e.target.value)}/>
                  </div>
                </>)}
              </div>

              <button className={s.btnPrimary} style={{width:'100%',padding:'12px'}} onClick={calcular}>Calcular Volume</button>

              {vol!==null&&(
                <div style={{marginTop:14,padding:'16px',background:'rgba(245,197,24,0.08)',border:'1px solid var(--accent)',borderRadius:'var(--radius-sm)',textAlign:'center'}}>
                  <div style={{fontSize:11,color:'var(--text3)',marginBottom:4}}>Volume calculado</div>
                  <div style={{fontSize:32,fontWeight:800,color:'var(--accent)',fontFamily:'var(--mono)'}}>{vol.toFixed(6)}<span style={{fontSize:14,marginLeft:4}}>m³</span></div>
                  {!form.nome&&<div style={{fontSize:11,color:'var(--red)',marginTop:8}}>Preencha o nome da peça para adicionar</div>}
                  {form.nome&&!saved&&<button className={s.btnPrimary} style={{marginTop:12,width:'100%'}} onClick={adicionar}>+ Adicionar ao Levantamento</button>}
                  {saved&&<div style={{marginTop:10,color:'var(--green)',fontSize:13,fontWeight:600}}>✓ Adicionado ao levantamento!</div>}
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* FORMULÁRIO ESCADA */}
      {tipoFeature==='escada'&&(
        <div style={{maxWidth:500}}>
          <button className={s.btnSecondary} style={{marginBottom:20}} onClick={()=>{setTipoFeature(null);setVol(null);setForm({});}}>← Voltar</button>
          <div className={s.panel}>
            <div className={s.panelTitle}>Escada / Rampa</div>
            <div style={{fontFamily:'var(--mono)',fontSize:11,color:'var(--text3)',marginBottom:16}}>
              Volume = (Comprimento × Largura × Altura) / 1.000.000
            </div>
            <div className={s.formGrid}>
              <div className={s.formGroup}>
                <label className={s.formLabel}>Andar</label>
                <input className={s.formInput} list="andares-list2" placeholder="ex: Térreo" value={form.andar||''} onChange={e=>upd('andar',e.target.value)}/>
                <datalist id="andares-list2">{andaresList.map(a=><option key={a} value={a}/>)}</datalist>
              </div>
              <div className={s.formGroup}>
                <label className={s.formLabel}>Nome</label>
                <input className={s.formInput} placeholder="ex: ESC-01" value={form.nome||''} onChange={e=>upd('nome',e.target.value)}/>
              </div>
              <div className={s.formGroup}>
                <label className={s.formLabel}>Comprimento [cm]</label>
                <input className={s.formInput} type="number" step="0.1" min="0" value={form.comp||''} onChange={e=>upd('comp',e.target.value)}/>
              </div>
              <div className={s.formGroup}>
                <label className={s.formLabel}>Largura [cm]</label>
                <input className={s.formInput} type="number" step="0.1" min="0" value={form.larg||''} onChange={e=>upd('larg',e.target.value)}/>
              </div>
              <div className={`${s.formGroup} ${s.formGroupFull}`}>
                <label className={s.formLabel}>Altura da Laje [cm]</label>
                <input className={s.formInput} type="number" step="0.1" min="0" value={form.alt||''} onChange={e=>upd('alt',e.target.value)}/>
              </div>
            </div>
            <button className={s.btnPrimary} style={{width:'100%',marginTop:14,padding:'12px'}} onClick={calcular}>Calcular Volume</button>
            {vol!==null&&(
              <div style={{marginTop:14,padding:'16px',background:'rgba(245,197,24,0.08)',border:'1px solid var(--accent)',borderRadius:'var(--radius-sm)',textAlign:'center'}}>
                <div style={{fontSize:11,color:'var(--text3)',marginBottom:4}}>Volume calculado</div>
                <div style={{fontSize:32,fontWeight:800,color:'var(--accent)',fontFamily:'var(--mono)'}}>{vol.toFixed(6)}<span style={{fontSize:14,marginLeft:4}}>m³</span></div>
                {form.nome&&!saved&&<button className={s.btnPrimary} style={{marginTop:12,width:'100%'}} onClick={adicionar}>+ Adicionar ao Levantamento</button>}
                {saved&&<div style={{marginTop:10,color:'var(--green)',fontSize:13,fontWeight:600}}>✓ Adicionado!</div>}
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

// ════════════════════════════════════════════════
// LEVANTAMENTO DE CONCRETO
// ════════════════════════════════════════════════
function PageLevantamento({ pecas, onEnviar }) {
  const [items, setItems]     = useState(getLevantamento);
  const [filtTipo, setFiltTipo] = useState('todos');
  const [filtAndar, setFiltAndar] = useState('todos');
  const [enviando, setEnviando] = useState(false);

  const tipos   = ['todos',...new Set(items.map(i=>i.tipo))];
  const andares = ['todos',...new Set(items.map(i=>i.andar)).values()].filter(Boolean);

  const filtrados = items.filter(i=>
    (filtTipo==='todos'||i.tipo===filtTipo)&&
    (filtAndar==='todos'||i.andar===filtAndar)
  );

  function remover(id) {
    const nova = items.filter(i=>i.id!==id);
    setItems(nova); setLevantamento(nova);
  }

  async function enviarParaBase() {
    if(!items.length) return;
    if(!confirm(`Enviar ${items.length} peças do levantamento para a base de dados?`)) return;
    setEnviando(true);
    try {
      const {apiAdicionarPecaLote} = await import('../lib/api');
      await apiAdicionarPecaLote(items.map(i=>({nome:i.nome,tipo:i.tipo,andar:i.andar,volume:i.volume})));
      onEnviar(`✓ ${items.length} peças enviadas para a base!`);
      setItems([]); setLevantamento([]);
    } catch(e){ alert('Erro: '+e.message); }
    finally{ setEnviando(false); }
  }

  return(
    <div className={s.page} style={{animation:'fadein 0.25s ease'}}>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:24,flexWrap:'wrap',gap:12}}>
        <div>
          <h2 style={{fontSize:22,fontWeight:800,color:'var(--text)',marginBottom:4}}>📋 Levantamento de Concreto</h2>
          <p style={{color:'var(--text3)',fontSize:13}}>{items.length} peça{items.length!==1?'s':''} no levantamento</p>
        </div>
        <button className={s.btnPrimary} disabled={!items.length||enviando} onClick={enviarParaBase}
          style={{padding:'12px 24px',opacity:items.length?1:0.5}}>
          {enviando?'⏳ Enviando...':'↑ Enviar para Base de Dados'}
        </button>
      </div>

      {/* Filtros */}
      <div style={{display:'flex',gap:12,marginBottom:20,flexWrap:'wrap'}}>
        <div>
          <label className={s.formLabel} style={{display:'block',marginBottom:6}}>Tipo</label>
          <select className={s.formSelect} value={filtTipo} onChange={e=>setFiltTipo(e.target.value)}>
            {tipos.map(t=><option key={t} value={t}>{t==='todos'?'Todos os tipos':t}</option>)}
          </select>
        </div>
        <div>
          <label className={s.formLabel} style={{display:'block',marginBottom:6}}>Andar</label>
          <select className={s.formSelect} value={filtAndar} onChange={e=>setFiltAndar(e.target.value)}>
            {andares.map(a=><option key={a} value={a}>{a==='todos'?'Todos os andares':a}</option>)}
          </select>
        </div>
      </div>

      {/* Lista */}
      {filtrados.length===0
        ?<div className={s.empty} style={{marginTop:40}}>
            {items.length===0
              ?<>Nenhuma peça calculada ainda.<br/>Use "Calcular Concreto" para adicionar.</>
              :'Nenhuma peça com estes filtros.'}
          </div>
        :<div className={s.panel} style={{padding:0}}>
          <table className={s.table}>
            <thead><tr><th>#</th><th>Nome</th><th>Tipo</th><th>Andar</th><th>Volume (m³)</th><th>Detalhes</th><th></th></tr></thead>
            <tbody>{filtrados.map((item,i)=>(
              <tr key={item.id}>
                <td className={s.tdMuted}>{i+1}</td>
                <td style={{fontWeight:600}}>{item.nome}</td>
                <td className={s.tdMono}>{item.tipo}</td>
                <td className={s.tdMono}>{item.andar||'—'}</td>
                <td className={s.tdAccent}>{item.volume.toFixed(6)}</td>
                <td className={s.tdMuted} style={{fontSize:11,maxWidth:200,whiteSpace:'normal'}}>{item.detalhes}</td>
                <td><button className={s.btnDanger} onClick={()=>remover(item.id)}>✕</button></td>
              </tr>
            ))}</tbody>
          </table>
          {/* Total */}
          <div style={{padding:'12px 16px',borderTop:'1px solid var(--border)',display:'flex',justifyContent:'flex-end',gap:24}}>
            <span style={{fontSize:13,color:'var(--text3)'}}>Total ({filtrados.length} peças):</span>
            <span style={{fontFamily:'var(--mono)',fontWeight:700,color:'var(--accent)',fontSize:15}}>
              {filtrados.reduce((s,i)=>s+i.volume,0).toFixed(4)} m³
            </span>
          </div>
        </div>
      }
    </div>
  );
}


