// MODAL: CALCULAR CONCRETO
// ════════════════════════════════════════════════
const PILAR_TIPOS = [
  { id:'ret',  label:'Retangular', icon:'▭', desc:'Seção retangular simples' },
  { id:'red',  label:'Redondo',    icon:'◯', desc:'Seção circular' },
  { id:'L',    label:'Tipo L',     icon:'⌐', desc:'Seção em forma de L' },
  { id:'T',    label:'Tipo T',     icon:'⊤', desc:'Seção em forma de T' },
];

function EsquemaPilar({ tipo }) {
  const W=170, H=170;
  if(tipo==='ret') return (
    <svg width={W} height={H} style={{display:'block',margin:'0 auto'}}>
      <rect x={30} y={20} width={100} height={120} fill="none" stroke="var(--accent)" strokeWidth={2}/>
      {/* A = largura, B = altura */}
      <line x1={30} y1={150} x2={130} y2={150} stroke="var(--blue)" strokeWidth={1} strokeDasharray="4,2"/>
      <text x={80} y={158} textAnchor="middle" fontSize={11} fill="var(--blue)" fontFamily="sans-serif">A</text>
      <line x1={140} y1={20} x2={140} y2={140} stroke="var(--green)" strokeWidth={1} strokeDasharray="4,2"/>
      <text x={152} y={84} textAnchor="middle" fontSize={11} fill="var(--green)" fontFamily="sans-serif">B</text>
      <text x={80} y={84} textAnchor="middle" fontSize={10} fill="var(--text3)" fontFamily="sans-serif">P.D.</text>
    </svg>
  );
  if(tipo==='red') return (
    <svg width={W} height={H} style={{display:'block',margin:'0 auto'}}>
      <ellipse cx={80} cy={80} rx={55} ry={55} fill="none" stroke="var(--accent)" strokeWidth={2}/>
      <line x1={80} y1={80} x2={135} y2={80} stroke="var(--blue)" strokeWidth={1.5} strokeDasharray="4,2"/>
      <text x={110} y={76} textAnchor="middle" fontSize={11} fill="var(--blue)" fontFamily="sans-serif">A (r)</text>
      <text x={80} y={84} textAnchor="middle" fontSize={10} fill="var(--text3)" fontFamily="sans-serif">P.D.</text>
    </svg>
  );
  if(tipo==='L') return (
    <svg viewBox="0 0 180 180" width={W} height={H} style={{display:'block',margin:'0 auto'}}>
      {/* Forma L: aba superior esquerda + base */}
      <path d="M15,10 L15,140 L145,140 L145,95 L55,95 L55,10 Z" fill="rgba(59,130,246,0.15)" stroke="var(--accent)" strokeWidth={2}/>
      {/* A = altura total (vertical esquerda) */}
      <line x1={12} y1={10} x2={12} y2={140} stroke="var(--blue)" strokeWidth={1.5} strokeDasharray="4,3"/>
      <text x={22} y={80} textAnchor="middle" fontSize={13} fill="var(--blue)" fontFamily="sans-serif" fontWeight="bold">A</text>
      {/* B = largura da aba superior */}
      <line x1={15} y1={8} x2={55} y2={8} stroke="var(--green)" strokeWidth={1.5} strokeDasharray="4,3"/>
      <text x={35} y={20} textAnchor="middle" fontSize={13} fill="var(--green)" fontFamily="sans-serif" fontWeight="bold">B</text>
      {/* C = largura total da base */}
      <line x1={15} y1={152} x2={145} y2={152} stroke="var(--red)" strokeWidth={1.5} strokeDasharray="4,3"/>
      <text x={80} y={166} textAnchor="middle" fontSize={13} fill="var(--red)" fontFamily="sans-serif" fontWeight="bold">C</text>
      {/* D = altura da base horizontal */}
      <line x1={148} y1={95} x2={148} y2={140} stroke="var(--purple)" strokeWidth={1.5} strokeDasharray="4,3"/>
      <text x={162} y={120} textAnchor="middle" fontSize={13} fill="var(--purple)" fontFamily="sans-serif" fontWeight="bold">D</text>
    </svg>
  );
  if(tipo==='T') return (
    <svg viewBox="0 0 180 180" width={W} height={H} style={{display:'block',margin:'0 auto'}}>
      {/* Forma T: aba superior + haste vertical */}
      <path d="M10,10 L150,10 L150,55 L95,55 L95,150 L65,150 L65,55 L10,55 Z" fill="rgba(59,130,246,0.15)" stroke="var(--accent)" strokeWidth={2}/>
      {/* A = largura total do topo */}
      <line x1={10} y1={7} x2={150} y2={7} stroke="var(--blue)" strokeWidth={1.5} strokeDasharray="4,3"/>
      <text x={80} y={20} textAnchor="middle" fontSize={13} fill="var(--blue)" fontFamily="sans-serif" fontWeight="bold">A</text>
      {/* B = espessura do topo */}
      <line x1={152} y1={10} x2={152} y2={55} stroke="var(--green)" strokeWidth={1.5} strokeDasharray="4,3"/>
      <text x={163} y={36} textAnchor="start" fontSize={13} fill="var(--green)" fontFamily="sans-serif" fontWeight="bold">B</text>
      {/* C = altura da haste */}
      <line x1={152} y1={55} x2={152} y2={150} stroke="var(--red)" strokeWidth={1.5} strokeDasharray="4,3"/>
      <text x={163} y={108} textAnchor="start" fontSize={13} fill="var(--red)" fontFamily="sans-serif" fontWeight="bold">C</text>
      {/* D = largura da haste */}
      <line x1={65} y1={153} x2={95} y2={153} stroke="var(--purple)" strokeWidth={1.5} strokeDasharray="4,3"/>
      <text x={80} y={166} textAnchor="middle" fontSize={13} fill="var(--purple)" fontFamily="sans-serif" fontWeight="bold">D</text>
    </svg>
  );
  return null;
}

function ModalCalcConcreto({ open, onClose, levantamento, setLevantamento, config, pecas }) {
  const [tipoPeca, setTipoPeca] = useState(null);
  const [tipoP, setTipoP] = useState('ret');
  const [andar, setAndar] = useState('');
  const [nome, setNome] = useState('');
  // Pilar
  const [peDireito, setPeDireito] = useState('');
  const [mA, setMA] = useState('');
  const [mB, setMB] = useState('');
  const [mC, setMC] = useState('');
  const [mD, setMD] = useState('');
  // Rampa
  const [comprimento, setComprimento] = useState('');
  const [largura, setLargura] = useState('');
  const [altLaje, setAltLaje] = useState('');
  // Escada — acordeão
  const [abaEscada, setAbaEscada] = useState(null); // null | 'laje' | 'patamar' | 'degrau'
  const [lajeInc, setLajeInc] = useState([{compIncl:'',larg:'',esp:''}]);
  const [patamares, setPatamares] = useState([{comp:'',larg:'',esp:''}]);
  const [degraus, setDegraus] = useState([{pisada:'',espelho:'',larg:'',qtd:''}]);

  const n = v => parseFloat(String(v).replace(',','.')) || 0;

  const volLajeInc  = lajeInc.reduce((s,l)  => s + (n(l.compIncl)*n(l.larg)*n(l.esp))/1000000, 0);
  const volPatamares= patamares.reduce((s,p) => s + (n(p.comp)*n(p.larg)*n(p.esp))/1000000, 0);
  const volDegraus  = degraus.reduce((s,d)   => s + (n(d.pisada)*n(d.espelho)/2*n(d.larg)*n(d.qtd))/1000000, 0);

  function calcVolume() {
    if(tipoPeca==='pilar') {
      const pd = n(peDireito);
      if(tipoP==='ret') return (pd*n(mA)*n(mB))/1000000;
      if(tipoP==='red') return ((Math.PI*n(mA)*n(mA)/4)*pd)/1000000;
      if(tipoP==='L')   return ((n(mA)*(n(mB)-n(mD)))+(n(mC)*n(mD)))*pd/1000000;
      if(tipoP==='T')   return ((n(mA)*n(mB))+(n(mC)*n(mD)))*pd/1000000;
    }
    if(tipoPeca==='rampa')  return (n(comprimento)*n(largura)*n(altLaje))/1000000;
    if(tipoPeca==='escada') return volLajeInc + volPatamares + volDegraus;
    return 0;
  }

  const volume = calcVolume();

  function adicionar() {
    if(!nome||!andar||volume<=0) return;
    setLevantamento(prev=>[...prev,{
      id:'lev_'+Date.now(),nome,andar,
      tipo:tipoPeca==='pilar'?'Pilar':tipoPeca==='escada'?'Escada':'Rampa',
      volume,
    }]);
    setNome('');setMA('');setMB('');setMC('');setMD('');setPeDireito('');
    setComprimento('');setLargura('');setAltLaje('');
    setLajeInc([{compIncl:'',larg:'',esp:''}]);
    setPatamares([{comp:'',larg:'',esp:''}]);
    setDegraus([{pisada:'',espelho:'',larg:'',qtd:''}]);
  }

  const PILAR_TIPOS=[
    {id:'ret',label:'Retangular',icon:'▭'},
    {id:'red',label:'Redondo',icon:'◯'},
    {id:'L',label:'Tipo L',icon:'⌐'},
    {id:'T',label:'Tipo T',icon:'⊤'},
  ];

  const rowBtn = (label,aba,vol) => (
    <div style={{marginBottom:8}}>
      <button onClick={()=>setAbaEscada(abaEscada===aba?null:aba)} style={{
        width:'100%',display:'flex',justifyContent:'space-between',alignItems:'center',
        padding:'12px 16px',border:'1px solid',borderRadius:'var(--radius-sm)',cursor:'pointer',
        background:abaEscada===aba?'rgba(245,197,24,0.1)':'var(--surface2)',
        borderColor:abaEscada===aba?'var(--accent)':'var(--border)',
        color:'var(--text)',
      }}>
        <span style={{fontWeight:700,fontSize:13}}>{abaEscada===aba?'▼':'>>'} {label}</span>
        <span style={{fontFamily:'var(--mono)',fontSize:12,color:vol>0?'var(--accent)':'var(--text3)'}}>
          {vol>0?vol.toFixed(4)+' m³':'—'}
        </span>
      </button>
    </div>
  );

  if(!open) return null;
  return (
    <div className={s.modalOverlay} onClick={e=>e.target===e.currentTarget&&onClose()}>
      <div className={`${s.modal} ${s.modalExtraWide}`}>
        <div className={s.modalTitle}>📐 Calcular Concreto</div>

        {!tipoPeca&&(
          <div>
            <div style={{marginBottom:16,fontSize:13,color:'var(--text3)'}}>Selecione o tipo de peça:</div>
            <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:12,marginBottom:20}}>
              {[
                {id:'pilar', icon:'▭',label:'Pilar', sub:'Ret, Redondo, L ou T'},
                {id:'rampa', icon:'⟋',label:'Rampa', sub:'Comp × Larg × Esp. Laje'},
                {id:'escada',icon:'🪜',label:'Escada',sub:'Laje + Patamares + Degraus'},
              ].map(t=>(
                <div key={t.id} onClick={()=>setTipoPeca(t.id)} className={s.menuCard} style={{textAlign:'center'}}>
                  <div style={{fontSize:36,marginBottom:8}}>{t.icon}</div>
                  <div className={s.menuCardTitle}>{t.label}</div>
                  <div className={s.menuCardSub}>{t.sub}</div>
                </div>
              ))}
            </div>
            <div className={s.btnRow}><button className={s.btnSecondary} onClick={onClose}>Fechar</button></div>
          </div>
        )}

        {tipoPeca==='pilar'&&(
          <div>
            <div style={{display:'flex',gap:8,marginBottom:16,flexWrap:'wrap'}}>
              {PILAR_TIPOS.map(t=>(
                <button key={t.id} onClick={()=>setTipoP(t.id)} style={{
                  display:'flex',flexDirection:'column',alignItems:'center',gap:4,padding:'10px 18px',
                  border:`2px solid ${tipoP===t.id?'var(--accent)':'var(--border)'}`,
                  background:tipoP===t.id?'rgba(245,197,24,0.1)':'var(--surface2)',
                  color:tipoP===t.id?'var(--accent)':'var(--text2)',cursor:'pointer',
                  borderRadius:'var(--radius-sm)',fontSize:13,fontWeight:tipoP===t.id?700:500,minWidth:80,
                }}>
                  <span style={{fontSize:22}}>{t.icon}</span>{t.label}
                </button>
              ))}
            </div>
            <div style={{display:'grid',gridTemplateColumns:'200px 1fr',gap:20,marginBottom:16}}>
              <div style={{background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:'var(--radius-sm)',padding:16,display:'flex',alignItems:'center',justifyContent:'center'}}>
                <EsquemaPilar tipo={tipoP}/>
              </div>
              <div style={{display:'flex',flexDirection:'column',gap:10}}>
                <div className={s.formGroup}><label className={s.formLabel}>Andar</label><AndarSelect value={andar} onChange={e=>setAndar(e.target.value)} config={config} pecas={pecas}/></div>
                <div className={s.formGroup}><label className={s.formLabel}>Nome</label><input className={s.formInput} placeholder="ex: P-01" value={nome} onChange={e=>setNome(e.target.value)}/></div>
                <div className={s.formGroup}><label className={s.formLabel}>Pé Direito [cm]</label><input className={s.formInput} type="number" placeholder="280" value={peDireito} onChange={e=>setPeDireito(e.target.value)}/></div>
                <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:8}}>
                  <div className={s.formGroup}><label className={s.formLabel} style={{color:'var(--blue)'}}>A [cm]</label><input className={s.formInput} type="number" value={mA} onChange={e=>setMA(e.target.value)}/></div>
                  {(tipoP==='ret'||tipoP==='L'||tipoP==='T')&&<div className={s.formGroup}><label className={s.formLabel} style={{color:'var(--green)'}}>B [cm]</label><input className={s.formInput} type="number" value={mB} onChange={e=>setMB(e.target.value)}/></div>}
                  {(tipoP==='L'||tipoP==='T')&&<div className={s.formGroup}><label className={s.formLabel} style={{color:'var(--red)'}}>C [cm]</label><input className={s.formInput} type="number" value={mC} onChange={e=>setMC(e.target.value)}/></div>}
                  {(tipoP==='L'||tipoP==='T')&&<div className={s.formGroup}><label className={s.formLabel} style={{color:'var(--purple)'}}>D [cm]</label><input className={s.formInput} type="number" value={mD} onChange={e=>setMD(e.target.value)}/></div>}
                </div>
              </div>
            </div>
            <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:'var(--radius-sm)',padding:'14px 20px',marginBottom:12}}>
              <div>
                <div style={{fontSize:11,color:'var(--text3)',textTransform:'uppercase',letterSpacing:1,marginBottom:4}}>Volume calculado</div>
                <div style={{fontFamily:'var(--mono)',fontSize:28,fontWeight:700,color:volume>0?'var(--accent)':'var(--text3)'}}>{volume>0?volume.toFixed(4):'-'} <span style={{fontSize:14}}>m³</span></div>
              </div>
              <button className={s.btnPrimary} disabled={!nome||!andar||volume<=0} onClick={adicionar} style={{padding:'12px 24px',fontSize:14}}>+ Adicionar ao Levantamento</button>
            </div>
            <div className={s.btnRow}><button className={s.btnSecondary} onClick={()=>setTipoPeca(null)}>← Voltar</button></div>
          </div>
        )}

        {tipoPeca==='rampa'&&(
          <div>
            <div style={{display:'grid',gridTemplateColumns:'180px 1fr',gap:20,marginBottom:16}}>
              <div style={{background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:'var(--radius-sm)',padding:12}}>
                <div style={{fontSize:10,fontWeight:700,color:'var(--text3)',textTransform:'uppercase',letterSpacing:1,marginBottom:8,textAlign:'center'}}>Rampa</div>
                <svg viewBox="0 0 180 120" width="100%" style={{display:'block'}}>
                  <rect x={15} y={15} width={140} height={80} fill="rgba(59,130,246,0.1)" stroke="var(--accent)" strokeWidth={2} rx={3}/>
                  <line x1={15} y1={103} x2={155} y2={103} stroke="var(--blue)" strokeWidth={1.5} strokeDasharray="4,2"/>
                  <text x={85} y={113} textAnchor="middle" fontSize={10} fill="var(--blue)" fontFamily="sans-serif" fontWeight="bold">Comprimento</text>
                  <line x1={162} y1={15} x2={162} y2={95} stroke="var(--green)" strokeWidth={1.5} strokeDasharray="4,2"/>
                  <text x={173} y={58} textAnchor="middle" fontSize={10} fill="var(--green)" fontFamily="sans-serif" fontWeight="bold" transform="rotate(90,173,58)">Largura</text>
                  <text x={85} y={59} textAnchor="middle" fontSize={11} fill="var(--red)" fontFamily="sans-serif" fontWeight="bold">E</text>
                </svg>
              </div>
              <div style={{display:'flex',flexDirection:'column',gap:10}}>
                <div className={s.formGroup}><label className={s.formLabel}>Andar</label><AndarSelect value={andar} onChange={e=>setAndar(e.target.value)} config={config} pecas={pecas}/></div>
                <div className={s.formGroup}><label className={s.formLabel}>Nome</label><input className={s.formInput} placeholder="ex: Rampa 01" value={nome} onChange={e=>setNome(e.target.value)}/></div>
                <div className={s.formGroup}><label className={s.formLabel} style={{color:'var(--blue)'}}>Comprimento [cm]</label><input className={s.formInput} type="number" placeholder="300" value={comprimento} onChange={e=>setComprimento(e.target.value)}/></div>
                <div className={s.formGroup}><label className={s.formLabel} style={{color:'var(--green)'}}>Largura [cm]</label><input className={s.formInput} type="number" placeholder="120" value={largura} onChange={e=>setLargura(e.target.value)}/></div>
                <div className={s.formGroup}><label className={s.formLabel} style={{color:'var(--red)'}}>E — Espessura da Laje [cm]</label><input className={s.formInput} type="number" placeholder="15" value={altLaje} onChange={e=>setAltLaje(e.target.value)}/></div>
              </div>
            </div>
            <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:'var(--radius-sm)',padding:'14px 20px',marginBottom:12}}>
              <div>
                <div style={{fontSize:11,color:'var(--text3)',textTransform:'uppercase',letterSpacing:1,marginBottom:4}}>Volume calculado</div>
                <div style={{fontFamily:'var(--mono)',fontSize:28,fontWeight:700,color:volume>0?'var(--accent)':'var(--text3)'}}>{volume>0?volume.toFixed(4):'-'} <span style={{fontSize:14}}>m³</span></div>
              </div>
              <button className={s.btnPrimary} disabled={!nome||!andar||volume<=0} onClick={adicionar} style={{padding:'12px 24px',fontSize:14}}>+ Adicionar ao Levantamento</button>
            </div>
            <div className={s.btnRow}><button className={s.btnSecondary} onClick={()=>setTipoPeca(null)}>← Voltar</button></div>
          </div>
        )}

        {tipoPeca==='escada'&&(
          <div>
            <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:16}}>
              <div className={s.formGroup}><label className={s.formLabel}>Andar</label><AndarSelect value={andar} onChange={e=>setAndar(e.target.value)} config={config} pecas={pecas}/></div>
              <div className={s.formGroup}><label className={s.formLabel}>Nome</label><input className={s.formInput} placeholder="ex: Escada 01" value={nome} onChange={e=>setNome(e.target.value)}/></div>
            </div>

            {/* ACORDEÃO 1 — LAJE INCLINADA */}
            {rowBtn('Laje Inclinada','laje',volLajeInc)}
            {abaEscada==='laje'&&(
              <div style={{border:'1px solid var(--accent)',borderTop:'none',borderRadius:'0 0 var(--radius-sm) var(--radius-sm)',padding:14,marginBottom:8,marginTop:-8}}>
                <div style={{display:'grid',gridTemplateColumns:'220px 1fr',gap:16,marginBottom:12}}>
                  <div style={{background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:'var(--radius-sm)',padding:10}}>
                    <svg viewBox="0 0 280 160" width="100%" style={{display:'block'}}>
                      {/* Laje inclinada — vista lateral */}
                      <polygon points="20,130 240,50 240,68 20,148" fill="rgba(245,197,24,0.18)" stroke="var(--accent)" strokeWidth={2.5}/>
                      {/* Cota comprimento inclinado — ao longo da laje */}
                      <line x1={20} y1={139} x2={240} y2={59} stroke="var(--blue)" strokeWidth={1.5} strokeDasharray="5,3"/>
                      <text x={130} y={105} textAnchor="middle" fontSize={11} fill="var(--blue)" fontFamily="sans-serif" fontWeight="bold" transform="rotate(-18,130,105)">Comp. inclinado</text>
                      {/* Cota E — perpendicular à superfície */}
                      <line x1={240} y1={50} x2={240} y2={68} stroke="var(--red)" strokeWidth={2}/>
                      <line x1={235} y1={50} x2={245} y2={50} stroke="var(--red)" strokeWidth={1.5}/>
                      <line x1={235} y1={68} x2={245} y2={68} stroke="var(--red)" strokeWidth={1.5}/>
                      <text x={256} y={62} textAnchor="start" fontSize={13} fill="var(--red)" fontFamily="sans-serif" fontWeight="bold">E</text>
                      {/* Largura — indicação de profundidade */}
                      <text x={80} y={148} textAnchor="middle" fontSize={11} fill="var(--green)" fontFamily="sans-serif" fontWeight="bold">Largura →</text>
                    </svg>
                  </div>
                  <div style={{fontSize:12,color:'var(--text3)',lineHeight:1.8}}>
                    <b style={{color:'var(--text2)'}}>Como medir:</b><br/>
                    Use o comprimento inclinado da escada diretamente do projeto (ex: 253.5 ou 260.5 cm).<br/>
                    <b style={{color:'var(--blue)'}}>Comp. inclinado</b> = medida diagonal da laje<br/>
                    <b style={{color:'var(--green)'}}>Largura</b> = largura da escada<br/>
                    <b style={{color:'var(--red)'}}>E</b> = espessura da laje
                  </div>
                </div>
                {lajeInc.map((l,i)=>(
                  <div key={i} style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr auto',gap:8,marginBottom:6,alignItems:'end'}}>
                    <div className={s.formGroup}><label className={s.formLabel} style={{color:'var(--blue)'}}>Comp. inclinado [cm]</label><input className={s.formInput} type="number" placeholder="260.5" value={l.compIncl} onChange={e=>setLajeInc(p=>p.map((x,j)=>j===i?{...x,compIncl:e.target.value}:x))}/></div>
                    <div className={s.formGroup}><label className={s.formLabel} style={{color:'var(--green)'}}>Largura [cm]</label><input className={s.formInput} type="number" placeholder="120" value={l.larg} onChange={e=>setLajeInc(p=>p.map((x,j)=>j===i?{...x,larg:e.target.value}:x))}/></div>
                    <div className={s.formGroup}><label className={s.formLabel} style={{color:'var(--red)'}}>E — Espessura [cm]</label><input className={s.formInput} type="number" placeholder="15" value={l.esp} onChange={e=>setLajeInc(p=>p.map((x,j)=>j===i?{...x,esp:e.target.value}:x))}/></div>
                    {lajeInc.length>1&&<button className={s.btnDanger} style={{marginBottom:2,padding:'5px 7px'}} onClick={()=>setLajeInc(p=>p.filter((_,j)=>j!==i))}>✕</button>}
                  </div>
                ))}
                <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginTop:8}}>
                  <button onClick={()=>setLajeInc(l=>[...l,{compIncl:'',larg:'',esp:''}])} style={{fontSize:12,padding:'4px 12px',background:'none',border:'1px solid var(--border)',color:'var(--text2)',borderRadius:'var(--radius-sm)',cursor:'pointer'}}>+ Adicionar lance</button>
                  <span style={{fontFamily:'var(--mono)',fontSize:12,color:'var(--accent)',fontWeight:700}}>Subtotal: {volLajeInc.toFixed(4)} m³</span>
                </div>
              </div>
            )}

            {/* ACORDEÃO 2 — PATAMARES */}
            {rowBtn('Patamares','patamar',volPatamares)}
            {abaEscada==='patamar'&&(
              <div style={{border:'1px solid var(--accent)',borderTop:'none',borderRadius:'0 0 var(--radius-sm) var(--radius-sm)',padding:14,marginBottom:8,marginTop:-8}}>
                <div style={{display:'grid',gridTemplateColumns:'220px 1fr',gap:16,marginBottom:12}}>
                  <div style={{background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:'var(--radius-sm)',padding:10}}>
                    <svg viewBox="0 0 280 150" width="100%" style={{display:'block'}}>
                      {/* Patamar — vista 3D simplificada */}
                      {/* Face frontal */}
                      <rect x={20} y={50} width={200} height={70} fill="rgba(59,130,246,0.15)" stroke="var(--accent)" strokeWidth={2.5}/>
                      {/* Face superior (perspectiva) */}
                      <polygon points="20,50 60,20 260,20 220,50" fill="rgba(59,130,246,0.08)" stroke="var(--accent)" strokeWidth={2}/>
                      {/* Face lateral direita */}
                      <polygon points="220,50 260,20 260,50 220,80" fill="rgba(59,130,246,0.05)" stroke="var(--accent)" strokeWidth={1.5}/>
                      {/* Cota Comprimento — base frontal */}
                      <line x1={20} y1={130} x2={220} y2={130} stroke="var(--blue)" strokeWidth={1.5} strokeDasharray="5,3"/>
                      <line x1={20} y1={125} x2={20} y2={135} stroke="var(--blue)" strokeWidth={1.5}/>
                      <line x1={220} y1={125} x2={220} y2={135} stroke="var(--blue)" strokeWidth={1.5}/>
                      <text x={120} y={145} textAnchor="middle" fontSize={12} fill="var(--blue)" fontFamily="sans-serif" fontWeight="bold">Comprimento</text>
                      {/* Cota E — espessura frontal */}
                      <line x1={5} y1={50} x2={5} y2={120} stroke="var(--red)" strokeWidth={1.5} strokeDasharray="5,3"/>
                      <line x1={1} y1={50} x2={9} y2={50} stroke="var(--red)" strokeWidth={1.5}/>
                      <line x1={1} y1={120} x2={9} y2={120} stroke="var(--red)" strokeWidth={1.5}/>
                      <text x={14} y={90} textAnchor="start" fontSize={13} fill="var(--red)" fontFamily="sans-serif" fontWeight="bold">E</text>
                      {/* Cota Largura — profundidade */}
                      <line x1={220} y1={50} x2={260} y2={20} stroke="var(--green)" strokeWidth={1.5} strokeDasharray="5,3"/>
                      <text x={248} y={30} textAnchor="start" fontSize={11} fill="var(--green)" fontFamily="sans-serif" fontWeight="bold">Larg.</text>
                    </svg>
                  </div>
                  <div style={{fontSize:12,color:'var(--text3)',lineHeight:1.8}}>
                    <b style={{color:'var(--text2)'}}>Patamar:</b> plataforma horizontal no início/fim/meio da escada.<br/>
                    <b style={{color:'var(--blue)'}}>Comprimento</b> = extensão horizontal<br/>
                    <b style={{color:'var(--green)'}}>Largura</b> = largura do patamar<br/>
                    <b style={{color:'var(--red)'}}>E</b> = espessura da laje do patamar
                  </div>
                </div>
                {patamares.map((p,i)=>(
                  <div key={i} style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr auto',gap:8,marginBottom:6,alignItems:'end'}}>
                    <div className={s.formGroup}><label className={s.formLabel} style={{color:'var(--blue)'}}>Comprimento [cm]</label><input className={s.formInput} type="number" placeholder="200" value={p.comp} onChange={e=>setPatamares(prev=>prev.map((x,j)=>j===i?{...x,comp:e.target.value}:x))}/></div>
                    <div className={s.formGroup}><label className={s.formLabel} style={{color:'var(--green)'}}>Largura [cm]</label><input className={s.formInput} type="number" placeholder="120" value={p.larg} onChange={e=>setPatamares(prev=>prev.map((x,j)=>j===i?{...x,larg:e.target.value}:x))}/></div>
                    <div className={s.formGroup}><label className={s.formLabel} style={{color:'var(--red)'}}>E — Espessura [cm]</label><input className={s.formInput} type="number" placeholder="15" value={p.esp} onChange={e=>setPatamares(prev=>prev.map((x,j)=>j===i?{...x,esp:e.target.value}:x))}/></div>
                    {patamares.length>1&&<button className={s.btnDanger} style={{marginBottom:2,padding:'5px 7px'}} onClick={()=>setPatamares(p=>p.filter((_,j)=>j!==i))}>✕</button>}
                  </div>
                ))}
                <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginTop:8}}>
                  <button onClick={()=>setPatamares(p=>[...p,{comp:'',larg:'',esp:''}])} style={{fontSize:12,padding:'4px 12px',background:'none',border:'1px solid var(--border)',color:'var(--text2)',borderRadius:'var(--radius-sm)',cursor:'pointer'}}>+ Adicionar patamar</button>
                  <span style={{fontFamily:'var(--mono)',fontSize:12,color:'var(--accent)',fontWeight:700}}>Subtotal: {volPatamares.toFixed(4)} m³</span>
                </div>
              </div>
            )}

            {/* ACORDEÃO 3 — DEGRAUS */}
            {rowBtn('Degraus','degrau',volDegraus)}
            {abaEscada==='degrau'&&(
              <div style={{border:'1px solid var(--accent)',borderTop:'none',borderRadius:'0 0 var(--radius-sm) var(--radius-sm)',padding:14,marginBottom:8,marginTop:-8}}>
                <div style={{display:'grid',gridTemplateColumns:'220px 1fr',gap:16,marginBottom:12}}>
                  <div style={{background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:'var(--radius-sm)',padding:10}}>
                    <svg viewBox="0 0 280 200" width="100%" style={{display:'block'}}>
                      {/* 3 degraus em vista lateral */}
                      <polygon points="20,170 90,170 90,127 160,127 160,84 230,84 230,55 160,55 160,84 90,84 90,127 20,127" fill="rgba(59,130,246,0.15)" stroke="var(--accent)" strokeWidth={2.5}/>
                      {/* Triângulo do degrau preenchido — mostra o volume */}
                      <polygon points="20,170 90,170 90,127" fill="rgba(245,197,24,0.2)" stroke="var(--accent)" strokeWidth={1} strokeDasharray="4,2"/>
                      {/* Cota Pisada — horizontal do degrau inferior */}
                      <line x1={20} y1={180} x2={90} y2={180} stroke="var(--blue)" strokeWidth={1.5}/>
                      <line x1={20} y1={175} x2={20} y2={185} stroke="var(--blue)" strokeWidth={1.5}/>
                      <line x1={90} y1={175} x2={90} y2={185} stroke="var(--blue)" strokeWidth={1.5}/>
                      <text x={55} y={195} textAnchor="middle" fontSize={11} fill="var(--blue)" fontFamily="sans-serif" fontWeight="bold">Pisada (P)</text>
                      {/* Cota Espelho — vertical do degrau */}
                      <line x1={8} y1={127} x2={8} y2={170} stroke="var(--green)" strokeWidth={1.5}/>
                      <line x1={3} y1={127} x2={13} y2={127} stroke="var(--green)" strokeWidth={1.5}/>
                      <line x1={3} y1={170} x2={13} y2={170} stroke="var(--green)" strokeWidth={1.5}/>
                      <text x={18} y={152} textAnchor="start" fontSize={11} fill="var(--green)" fontFamily="sans-serif" fontWeight="bold">Espelho (E)</text>
                      {/* Linha indicando N degraus */}
                      <line x1={20} y1={170} x2={230} y2={55} stroke="var(--purple)" strokeWidth={1.5} strokeDasharray="6,3" opacity={0.7}/>
                      <text x={145} y={48} textAnchor="middle" fontSize={11} fill="var(--purple)" fontFamily="sans-serif" fontWeight="bold">N degraus</text>
                      {/* Largura */}
                      <text x={240} y={75} textAnchor="start" fontSize={11} fill="var(--red)" fontFamily="sans-serif" fontWeight="bold">Larg.</text>
                      <text x={100} y={175} textAnchor="middle" fontSize={9} fill="var(--text3)" fontFamily="sans-serif">V = P × E / 2 × Larg × N</text>
                    </svg>
                  </div>
                  <div style={{fontSize:12,color:'var(--text3)',lineHeight:1.8}}>
                    <b style={{color:'var(--text2)'}}>Degraus:</b> volume do triângulo formado por cada degrau.<br/>
                    <b style={{color:'var(--blue)'}}>Pisada (P)</b> = profundidade horizontal do degrau (ex: 27 cm)<br/>
                    <b style={{color:'var(--green)'}}>Espelho (E)</b> = altura vertical do degrau (ex: 17.65 cm)<br/>
                    <b style={{color:'var(--purple)'}}>Largura</b> = largura da escada<br/>
                    <b>N</b> = número de degraus
                  </div>
                </div>
                {degraus.map((d,i)=>(
                  <div key={i} style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr 60px auto',gap:8,marginBottom:6,alignItems:'end'}}>
                    <div className={s.formGroup}><label className={s.formLabel} style={{color:'var(--blue)'}}>Pisada P [cm]</label><input className={s.formInput} type="number" placeholder="27" value={d.pisada} onChange={e=>setDegraus(p=>p.map((x,j)=>j===i?{...x,pisada:e.target.value}:x))}/></div>
                    <div className={s.formGroup}><label className={s.formLabel} style={{color:'var(--green)'}}>Espelho E [cm]</label><input className={s.formInput} type="number" placeholder="17.65" value={d.espelho} onChange={e=>setDegraus(p=>p.map((x,j)=>j===i?{...x,espelho:e.target.value}:x))}/></div>
                    <div className={s.formGroup}><label className={s.formLabel} style={{color:'var(--purple)'}}>Largura [cm]</label><input className={s.formInput} type="number" placeholder="120" value={d.larg} onChange={e=>setDegraus(p=>p.map((x,j)=>j===i?{...x,larg:e.target.value}:x))}/></div>
                    <div className={s.formGroup}><label className={s.formLabel}>N degraus</label><input className={s.formInput} type="number" placeholder="12" value={d.qtd} onChange={e=>setDegraus(p=>p.map((x,j)=>j===i?{...x,qtd:e.target.value}:x))}/></div>
                    {degraus.length>1&&<button className={s.btnDanger} style={{marginBottom:2,padding:'5px 7px'}} onClick={()=>setDegraus(p=>p.filter((_,j)=>j!==i))}>✕</button>}
                  </div>
                ))}
                <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginTop:8}}>
                  <button onClick={()=>setDegraus(d=>[...d,{pisada:'',espelho:'',larg:'',qtd:''}])} style={{fontSize:12,padding:'4px 12px',background:'none',border:'1px solid var(--border)',color:'var(--text2)',borderRadius:'var(--radius-sm)',cursor:'pointer'}}>+ Adicionar lance</button>
                  <span style={{fontFamily:'var(--mono)',fontSize:12,color:'var(--accent)',fontWeight:700}}>Subtotal: {volDegraus.toFixed(4)} m³</span>
                </div>
              </div>
            )}

            <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:'var(--radius-sm)',padding:'14px 20px',marginTop:16,marginBottom:12}}>
              <div>
                <div style={{fontSize:11,color:'var(--text3)',textTransform:'uppercase',letterSpacing:1,marginBottom:4}}>Volume Total (Laje + Patamares + Degraus)</div>
                <div style={{fontFamily:'var(--mono)',fontSize:28,fontWeight:700,color:volume>0?'var(--accent)':'var(--text3)'}}>{volume>0?volume.toFixed(4):'-'} <span style={{fontSize:14}}>m³</span></div>
              </div>
              <button className={s.btnPrimary} disabled={!nome||!andar||volume<=0} onClick={adicionar} style={{padding:'12px 24px',fontSize:14}}>+ Adicionar ao Levantamento</button>
            </div>
            <div className={s.btnRow}><button className={s.btnSecondary} onClick={()=>setTipoPeca(null)}>← Voltar</button></div>
          </div>
        )}
      </div>
    </div>
  );
}


// ════════════════════════════════════════════════
// MODAL: LEVANTAMENTO DE CONCRETO
// ════════════════════════════════════════════════
function ModalLevantamento({ open, onClose, levantamento, setLevantamento, onEnviarBase }) {
  const [filtroTipo,  setFiltroTipo]  = useState('todos');
  const [filtroAndar, setFiltroAndar] = useState('todos');
  const [selecionados, setSelecionados] = useState(new Set());

  const tipos   = ['todos',...new Set(levantamento.map(p=>p.tipo))];
  const andares = ['todos',...new Set(levantamento.map(p=>p.andar))].sort();

  const filtrado = levantamento.filter(p=>
    (filtroTipo==='todos'||p.tipo===filtroTipo)&&
    (filtroAndar==='todos'||p.andar===filtroAndar)
  );

  function toggleSel(id) {
    setSelecionados(prev=>{ const n=new Set(prev); n.has(id)?n.delete(id):n.add(id); return n; });
  }

  function remover(id) {
    setLevantamento(prev=>prev.filter(p=>p.id!==id));
    setSelecionados(prev=>{ const n=new Set(prev); n.delete(id); return n; });
  }

  function enviarSelecionados() {
    const itens = levantamento.filter(p=>selecionados.has(p.id));
    if(!itens.length){alert('Selecione pelo menos uma peça');return;}
    onEnviarBase(itens);
    setSelecionados(new Set());
  }

  if(!open) return null;
  return(
    <div className={s.modalOverlay} onClick={e=>e.target===e.currentTarget&&onClose()}>
      <div className={`${s.modal} ${s.modalExtraWide}`}>
        <div className={s.modalTitle}>📋 Levantamento de Concreto
          <span style={{fontFamily:'var(--mono)',fontSize:11,color:'var(--text3)',fontWeight:400,marginLeft:8}}>{levantamento.length} peças</span>
        </div>

        {/* Filtros */}
        <div style={{display:'flex',gap:10,marginBottom:16,flexWrap:'wrap',alignItems:'center'}}>
          <select className={s.formSelect} style={{minWidth:140}} value={filtroTipo} onChange={e=>setFiltroTipo(e.target.value)}>
            {tipos.map(t=><option key={t} value={t}>{t==='todos'?'Todos os tipos':t}</option>)}
          </select>
          <select className={s.formSelect} style={{minWidth:160}} value={filtroAndar} onChange={e=>setFiltroAndar(e.target.value)}>
            {andares.map(a=><option key={a} value={a}>{a==='todos'?'Todos os andares':a}</option>)}
          </select>
          <span style={{fontFamily:'var(--mono)',fontSize:12,color:'var(--text3)',marginLeft:'auto'}}>
            {selecionados.size} selecionada{selecionados.size!==1?'s':''}
          </span>
          <button className={s.btnPrimary} disabled={!selecionados.size} onClick={enviarSelecionados} style={{padding:'9px 18px'}}>
            → Enviar para Base de Peças
          </button>
        </div>

        {levantamento.length===0
          ?<div className={s.empty}>Nenhuma peça no levantamento.<br/>Use "Calcular Concreto" para adicionar.</div>
          :<div style={{maxHeight:440,overflowY:'auto',border:'1px solid var(--border)',borderRadius:'var(--radius-sm)'}}>
            <table className={s.table} style={{tableLayout:'fixed',width:'100%'}}>
              <thead><tr>
                <th style={{width:36}}>
                  <input type="checkbox" onChange={e=>{
                    if(e.target.checked) setSelecionados(new Set(filtrado.map(p=>p.id)));
                    else setSelecionados(new Set());
                  }} checked={filtrado.length>0&&filtrado.every(p=>selecionados.has(p.id))}/>
                </th>
                <th>Nome</th><th>Tipo</th><th>Andar</th><th style={{textAlign:'right'}}>Volume (m³)</th><th style={{width:40}}></th>
              </tr></thead>
              <tbody>
                {filtrado.map(p=>(
                  <tr key={p.id}>
                    <td><input type="checkbox" checked={selecionados.has(p.id)} onChange={()=>toggleSel(p.id)}/></td>
                    <td style={{fontWeight:600}}>{p.nome}</td>
                    <td className={s.tdMono}>{p.tipo}</td>
                    <td className={s.tdMono}>{p.andar}</td>
                    <td className={s.tdAccent} style={{textAlign:'right'}}>{p.volume.toFixed(4)}</td>
                    <td><button className={s.btnDanger} onClick={()=>remover(p.id)} style={{padding:'3px 8px'}}>✕</button></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        }

        <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginTop:14}}>
          <span style={{fontFamily:'var(--mono)',fontSize:12,color:'var(--text3)'}}>
            Total: {fmt4(filtrado.reduce((s,p)=>s+p.volume,0))} m³
          </span>
          <button className={s.btnSecondary} onClick={onClose}>Fechar</button>
        </div>
      </div>
    </div>
  );
}

// ════════════════════════════════════════════════
// PÁGINA PRINCIPAL
// ════════════════════════════════════════════════
export default function Home() {
  const [modalPecas,setModalPecas]=useState(false);
  const [modalConc,setModalConc]=useState(false);
  const [modalBT,setModalBT]=useState(false);
  const [modalConfig,setModalConfig]=useState(false);
  const [modalCalc,setModalCalc]=useState(false);
  const [modalLevantamento,setModalLevantamento]=useState(false);
  const [levantamento,setLevantamento]=useState([]);
  const [modalCalcConc,setModalCalcConc]=useState(false);
  const {data,loading,error,refresh}=useData();
  const {pecas,concretagens,pecaConc,btsConfig,lancamentos}=data;
  const [config, salvarConfig] = useConfigObra();

  const [tab,setTab]=useState('operacional');
  const [filtroAndar,setFiltroAndar]=useState('todos');
  const [filtroConc,setFiltroConc]=useState('todas');
  const [filtroTipoOp,setFiltroTipoOp]=useState('todos');
  const [filtroRelConc,setFiltroRelConc]=useState('todas');
  const [filtroRelAndar,setFiltroRelAndar]=useState('todos');
  const [toast,setToast]=useState({msg:'',tipo:'ok'});
  const [clock,setClock]=useState('');

  useEffect(()=>{ const t=()=>setClock(new Date().toLocaleTimeString('pt-BR')); t(); const id=setInterval(t,1000); return()=>clearInterval(id); },[]);
  useEffect(()=>{ if(tab==='calcular'){setModalCalc(true);setTab('operacional');} },[tab]);
  const showToast=(msg,tipo='ok')=>{setToast({msg,tipo});setTimeout(()=>refresh(),1500);};

  const ordemAndares = config.ordemAndares||[];
  const andares = ordenarAndares([...new Set(pecas.map(p=>p.andar))], ordemAndares);
  const TIPO_ORDEM = ['Pilar','Viga','Laje','Escada','Rampa','Fundação','Cortina','Outro'];
  const tipos = TIPO_ORDEM.filter(t=>[...new Set(pecas.map(p=>p.tipo))].includes(t))
    .concat([...new Set(pecas.map(p=>p.tipo))].filter(t=>!TIPO_ORDEM.includes(t)).sort());
  // Filtrar peças pelo filtroConc para KPIs
  const _vcsKPI = filtroConc==='todas' ? [] : pecaConc.filter(pc=>pc.concretagemId===filtroConc);
  const pecasParaKPI = filtroConc==='todas' ? pecas :
    pecas
      .filter(p=>_vcsKPI.some(pc=>pc.pecaId===p.id))
      .map(p=>{
        const vc = _vcsKPI.find(pc=>pc.pecaId===p.id);
        const pct = (vc && parseFloat(vc.pctConcretagem)>0) ? parseFloat(vc.pctConcretagem) : 100;
        return {...p, volume: +(p.volume * pct / 100).toFixed(6)};
      });
  const btsParaKPI = filtroConc==='todas' ? btsConfig : btsConfig.filter(b=>b.concretagemId===filtroConc);
  const lansParaKPI = filtroConc==='todas' ? lancamentos : lancamentos.filter(l=>l.concretagemId===filtroConc);
  const kpis    = calcKPIs(pecasParaKPI,lansParaKPI,btsParaKPI,filtroAndar);
  const perdaInfo = kpis.perdaInfo;
  // Usar lancamentos filtrados para progresso por tipo
  const lancamentosOp = filtroConc==='todas' ? lancamentos : lancamentos.filter(l=>l.concretagemId===filtroConc);

  const pecasFiltOp=pecas.filter(p=>
    (filtroAndar==='todos'||p.andar===filtroAndar)&&
    (filtroTipoOp==='todos'||p.tipo===filtroTipoOp)&&
    (filtroConc==='todas'||pecaConc.filter(pc=>pc.concretagemId===filtroConc).map(pc=>pc.pecaId).includes(p.id))
  );

  const ultimoLan=lancamentos[lancamentos.length-1];
  const ultimaBTConf=ultimoLan?btsConfig.find(b=>b.id===ultimoLan.btConfigId):null;
  const ultimaConc=ultimaBTConf?concretagens.find(c=>c.id===ultimaBTConf.concretagemId):null;
  const volUltimaBT=ultimoLan?lancamentos.filter(l=>l.btConfigId===ultimoLan.btConfigId).reduce((s,l)=>s+l.volume,0):0;
  const perdaUltima=ultimaBTConf?ultimaBTConf.volumePrevisto-volUltimaBT:0;

  const ICONES_KPI = ['📦','✅','📊','⚠️','📉'];

  if(loading) return <div className={s.loadingWrap}><div className={s.loadingText}>CARREGANDO DADOS...</div></div>;
  if(error) return <div className={s.errorPanel}><div>⚠ Falha ao carregar dados</div><div style={{color:'var(--text2)',marginTop:8}}>{error}</div><button className={s.refreshBtn} onClick={refresh}>↻ Tentar novamente</button></div>;

  return(
    <div className={s.layout}>

      {/* ── SIDEBAR ── */}
      <aside className={s.sidebar}>
        <div className={s.sidebarLogo}>
          <img src={LOGO_ICON} className={s.sidebarLogoIcon} alt="logo"/>
          <div className={s.sidebarLogoText}>
            <span className={s.sidebarLogoName}>{config.nomeObra||'Concreto'}</span>
            <span className={s.sidebarLogoSub}>Controle de Concretagem</span>
          </div>
        </div>

        <nav className={s.sidebarNav}>
          <div style={{padding:'8px 20px 4px',fontSize:10,fontWeight:700,color:'var(--text3)',letterSpacing:2,textTransform:'uppercase'}}>Principal</div>
          <button className={`${s.sidebarItem} ${tab==='operacional'?s.sidebarItemActive:''}`} onClick={()=>setTab('operacional')}>
            <span className={s.sidebarItemIcon}>⬡</span> Operacional
          </button>
          <button className={`${s.sidebarItem} ${tab==='relatorios'?s.sidebarItemActive:''}`} onClick={()=>setTab('relatorios')}>
            <span className={s.sidebarItemIcon}>📊</span> Relatórios
          </button>
          <button className={`${s.sidebarItem} ${tab==='notas'?s.sidebarItemActive:''}`} onClick={()=>setTab('notas')}>
            <span className={s.sidebarItemIcon}>📝</span> Notas de Versão
          </button>
          <div style={{padding:'16px 20px 4px',fontSize:10,fontWeight:700,color:'var(--text3)',letterSpacing:2,textTransform:'uppercase'}}>Levantamento</div>
          <button className={s.sidebarItem} onClick={()=>setModalCalc(true)}>
            <span className={s.sidebarItemIcon}>📐</span> Calcular Concreto
          </button>
          <button className={s.sidebarItem} onClick={()=>setModalLevantamento(true)}>
            <span className={s.sidebarItemIcon}>📋</span> Levantamento
            {levantamento.length>0&&<span style={{marginLeft:'auto',background:'var(--accent)',color:'#111',fontSize:10,fontWeight:700,padding:'2px 7px',borderRadius:10}}>{levantamento.length}</span>}
          </button>
          <div style={{padding:'16px 20px 4px',fontSize:10,fontWeight:700,color:'var(--text3)',letterSpacing:2,textTransform:'uppercase'}}>Sistema</div>
          <button className={s.sidebarItem} onClick={()=>setModalConfig(true)}>
            <span className={s.sidebarItemIcon}>⚙</span> Configurações
          </button>
        </nav>

        <div className={s.sidebarBottom}>
          <img src={OBRA_IMG} className={s.sidebarObraImg} alt="obra"/>
        </div>
      </aside>

      {/* ── CONTEÚDO PRINCIPAL ── */}
      <div className={s.mainContent}>

        {/* HEADER */}
        <header className={s.header}>
          <div style={{flex:1}}/>
          <div className={s.headerRight}>
            <div className={s.headerClock}><div className={s.liveDot}/>{clock}</div>
            <button className={s.headerBtn} onClick={()=>setModalConfig(true)}>⚙ Configurações</button>
            <button className={s.headerBtn} onClick={refresh}>↻ Atualizar</button>
          </div>
        </header>

        {/* ══ OPERACIONAL ══ */}
        {tab==='operacional'&&(
          <main className={`${s.page} animate-fadein`}>

            {/* FILTROS */}
            <FiltroBar
              andares={andares}
              concretagens={concretagens}
              pecaConc={pecaConc}
              pecas={pecas}
              filtroAndar={filtroAndar}
              setFiltroAndar={setFiltroAndar}
              filtroConc={filtroConc}
              setFiltroConc={setFiltroConc}
            />

            {/* DEBUG VISUAL TEMPORÁRIO */}
            {filtroConc!=='todas'&&(
              <div style={{background:'rgba(255,0,0,0.1)',border:'1px solid red',padding:'8px 12px',marginBottom:8,fontSize:11,fontFamily:'monospace'}}>
                filtroConc: {filtroConc} | 
                pecaConc matches: {pecaConc.filter(pc=>pc.concretagemId===filtroConc).length} |
                pecaConc total: {pecaConc.length} |
                concretagem IDs no pecaConc: {[...new Set(pecaConc.map(pc=>pc.concretagemId))].join(', ')}
              </div>
            )}

            {/* KPIs */}
            <div className={s.kpiGrid}>
              {[
                {label:'Volume Total do Projeto', value:fmt4(kpis.totalVol), unit:'m³', sub:filtroConc==='todas'?`${pecas.length} peças cadastradas`:`${pecasParaKPI.length} peças nesta concretagem`, icon:'📦', v:''},
                {label:'Volume Real Concretado',  value:fmt4(kpis.concVol),  unit:'m³', sub:`${fmt1(kpis.pctConc)}% do projeto`,   icon:'✅', v:'green'},
                {label:'Faltando (Real)',         value:fmt4(kpis.realFaltando), unit:'m³', sub:'proj. − real concretado', icon:'⚠️', v:'red'},
                {label:'Faltando (Projeto)',      value:fmt4(kpis.projFaltando), unit:'m³', sub:'proj. − BTs executadas', icon:'📊', v:'blue'},
                {label:'Índice de Perda',         value:fmt1(perdaInfo.indice),  unit:'%',  sub:`média por BT · ${fmt4(perdaInfo.perdaTotal)} m³`, icon:'📉', v:'orange'},
              ].map((k,i)=>(
                <div key={i} className={`${s.kpi} ${k.v==='green'?s.kpiGreen:k.v==='red'?s.kpiRed:k.v==='blue'?s.kpiBlue:k.v==='orange'?s.kpiOrange:''}`}>
                  <div className={s.kpiIcon}>{k.icon}</div>
                  <div className={s.kpiBody}>
                    <div className={s.kpiLabel}>{k.label}</div>
                    <div className={s.kpiValue}>{k.value}<span className={s.kpiUnit}>{k.unit}</span></div>
                    <div className={s.kpiSub}>{k.sub}</div>
                  </div>
                </div>
              ))}
            </div>

            {/* LAUNCH BAR */}
            <div className={s.launchBar}>
              <div className={s.launchBarBg} style={{backgroundImage:`url(${OBRA_IMG})`}}/>
              <div className={s.launchBarOverlay}/>
              <div className={s.launchBarContent}>
                <div className={s.launchBarLeft}>
                  <div className={s.launchBarBadge}>⚡ Pronto para Lançamento</div>
                  <div className={s.launchBarTitle}>Lançamento de Concretagem</div>
                  <div className={s.launchBarSub}>Gerencie peças, configure concretagens e lance BTs com agilidade.</div>
                </div>
                <div className={s.launchBarRight}>
                  <div className={s.launchBarActions}>
                    <button className={s.launchBarSmallBtn} onClick={()=>setModalPecas(true)}>
                      <span className={s.launchBarSmallBtnIcon}>◻</span>
                      Peças
                      <span className={s.launchBarSmallBtnSub}>Gerenciar peças</span>
                    </button>
                    <button className={s.launchBarSmallBtn} onClick={()=>setModalConc(true)}>
                      <span className={s.launchBarSmallBtnIcon}>◈</span>
                      Concretagens
                      <span className={s.launchBarSmallBtnSub}>Gerenciar concretagens</span>
                    </button>
                  </div>
                  <button className={s.btnLaunch} onClick={()=>setModalBT(true)}>
                    ⊕ LANÇAR BT →
                  </button>
                </div>
              </div>
            </div>

            {/* GRID PRINCIPAL */}
            <div className={s.grid2}>
              {/* Progresso por tipo */}
              <div className={s.panel}>
                <div className={s.panelTitle}>Progresso por Tipo
                  <span style={{fontFamily:'var(--mono)',fontSize:10,color:'var(--text3)',fontWeight:400,marginLeft:6}}>▼ clique para ver peças</span>
                </div>
                <GraficoTipos pecas={pecasFiltOp} lancamentos={lancamentosOp}/>
              </div>

              {/* Última BT + Status BTs */}
              <div>
                {ultimaBTConf&&(
                  <div className={s.lastBtPanel}>
                    <div className={s.lastBtBadge}>Última BT</div>
                    <div className={s.lastBtNum}>BT-{ultimaBTConf.numero}</div>
                    <div className={s.lastBtGrid}>
                      <div className={s.lastBtItem}>
                        <span className={s.lastBtItemLabel}>Concretagem</span>
                        <span className={s.lastBtItemValue} style={{color:'var(--accent)'}}>Nº {ultimaConc?.numero||'—'}</span>
                      </div>
                      <div className={s.lastBtItem}>
                        <span className={s.lastBtItemLabel}>Previsto</span>
                        <span className={s.lastBtItemValue}>{fmt4(ultimaBTConf.volumePrevisto)} m³</span>
                      </div>
                      <div className={s.lastBtItem}>
                        <span className={s.lastBtItemLabel}>Executado</span>
                        <span className={s.lastBtItemValue} style={{color:'var(--green)'}}>{fmt4(volUltimaBT)} m³</span>
                      </div>
                      <div className={s.lastBtItem}>
                        <span className={s.lastBtItemLabel}>{perdaUltima>=0?'Perda Caminhão':'Sobra Inesperada'}</span>
                        <span className={s.lastBtItemValue} style={{color:perdaUltima>0?'var(--red)':'var(--blue)'}}>{fmt4(Math.abs(perdaUltima))} m³</span>
                      </div>
                    </div>
                    <div style={{marginTop:12}}>
                      <span className={`${s.badge} ${s.badgeComplete}`}>Concluído ✓</span>
                    </div>
                    <button className={s.lastBtBtn} onClick={()=>setModalBT(true)}>Ver detalhes da BT →</button>
                  </div>
                )}

                <div className={s.panel}>
                  <div className={s.panelTitle}>Status das BTs por Concretagem</div>
                  <GraficoBTs
                    btsConfig={filtroConc!=='todas' ? btsConfig.filter(b=>b.concretagemId===filtroConc) :
                      filtroAndar!=='todos' ? btsConfig.filter(b=>{
                        const ids=pecaConc.filter(pc=>pc.concretagemId===b.concretagemId).map(pc=>pc.pecaId);
                        return pecas.some(p=>ids.includes(p.id)&&p.andar===filtroAndar);
                      }) : btsConfig}
                    lancamentos={filtroConc!=='todas' ? lancamentos.filter(l=>l.concretagemId===filtroConc) :
                      filtroAndar!=='todos' ? lancamentos.filter(l=>{
                        const p=pecas.find(p=>p.id===l.pecaId);
                        return p&&p.andar===filtroAndar;
                      }) : lancamentos}
                    concretagens={filtroConc!=='todas' ? concretagens.filter(c=>c.id===filtroConc) :
                      filtroAndar!=='todos' ? concretagens.filter(c=>{
                        const ids=pecaConc.filter(pc=>pc.concretagemId===c.id).map(pc=>pc.pecaId);
                        return pecas.some(p=>ids.includes(p.id)&&p.andar===filtroAndar);
                      }) : concretagens}
                  />
                </div>
              </div>
            </div>

            {/* Dica */}
            <div style={{display:'flex',alignItems:'center',gap:8,padding:'12px 16px',background:'var(--surface)',borderRadius:'var(--radius)',border:'1px solid var(--border)',color:'var(--text3)',fontSize:12}}>
              <span style={{color:'var(--accent)'}}>💡</span>
              <span><strong style={{color:'var(--text2)'}}>Dica:</strong> Mantenha os cadastros de peças atualizados para índices mais precisos.</span>
            </div>
          </main>
        )}

        {/* ══ RELATÓRIOS ══ */}
        {tab==='relatorios'&&(
          <main className={`${s.page} animate-fadein`}>
            <div className={s.panel} style={{marginBottom:20}}>
              <div className={s.panelTitle}>Filtros</div>
              <div style={{display:'flex',gap:16,flexWrap:'wrap'}}>
                <div><label className={s.formLabel} style={{display:'block',marginBottom:6}}>Concretagem</label>
                  <select className={s.formSelect} style={{maxWidth:300}} value={filtroRelConc} onChange={e=>setFiltroRelConc(e.target.value)}>
                    <option value="todas">Todas</option>
                    {[...concretagens].sort((a,b)=>a.numero-b.numero).map(c=><option key={c.id} value={c.id}>Nº {c.numero} — {c.data}{c.descricao?` | ${c.descricao}`:''}</option>)}
                  </select>
                </div>
                <div><label className={s.formLabel} style={{display:'block',marginBottom:6}}>Andar</label>
                  <select className={s.formSelect} style={{maxWidth:220}} value={filtroRelAndar} onChange={e=>setFiltroRelAndar(e.target.value)}>
                    <option value="todos">Todos</option>
                    {andares.map(a=><option key={a} value={a}>{a}</option>)}
                  </select>
                </div>
              </div>
            </div>

            {(()=>{
              let lans=lancamentos, pcs=pecas, bts=btsConfig;
              if(filtroRelConc!=='todas'){
                lans=lans.filter(l=>l.concretagemId===filtroRelConc);
                bts=bts.filter(b=>b.concretagemId===filtroRelConc);
                // Filtrar peças vinculadas a esta concretagem
                const pecaIdsConc=pecaConc.filter(pc=>pc.concretagemId===filtroRelConc).map(pc=>pc.pecaId);
                pcs=pcs.filter(p=>pecaIdsConc.includes(p.id));
              }
              if(filtroRelAndar!=='todos') pcs=pcs.filter(p=>p.andar===filtroRelAndar);
              const pids=new Set(pcs.map(p=>p.id));lans=lans.filter(l=>pids.has(l.pecaId));
              const relProg=pcs.reduce((s,p)=>s+p.volume,0);
              const relConc=pcs.reduce((s,p)=>s+Math.min(p.volume,volLancadoPeca(p.id,lans)),0);
              const pInfo=calcIndicePerda(lans,bts);
              const prevVol=calcVolumePrevisto(bts,lans);
              const CORES=['#e8a225','#4a9eff','#3ecf7a','#e85a4f','#a855f7'];
              const donutDados=[{val:relConc,cor:'var(--green)',label:'Executado'},{val:Math.max(0,relProg-relConc),cor:'var(--border2)',label:'Faltando'}].filter(d=>d.val>0);
              const donutPerda=[{val:pInfo.perdaObra,cor:'var(--red)',label:'Perda Obra'},{val:Math.max(0,pInfo.perdaCaminhao),cor:'var(--orange)',label:'Perda Caminhão'},{val:pInfo.totalExecutado,cor:'var(--green)',label:'Executado'}].filter(d=>d.val>0);

              return(
                <>
                  <div className={s.grid4} style={{marginBottom:20}}>
                    {[
                      {label:'Vol. Programado',  value:fmt4(relProg),         unit:'m³', v:''},
                      {label:'Vol. Concretado',  value:fmt4(relConc),         unit:'m³', sub:`${fmt1(relProg>0?relConc/relProg*100:0)}%`, v:'green'},
                      {label:'Perda em Obra',    value:fmt4(pInfo.perdaObra), unit:'m³', sub:`${fmt1(pInfo.totalPrevisto>0?pInfo.perdaObra/pInfo.totalPrevisto*100:0)}%`, v:'red'},
                      {label:'Índice de Perda',  value:fmt1(pInfo.indice),    unit:'%',  sub:'média por BT', v:'orange'},
                    ].map((k,i)=>(
                      <div key={i} className={`${s.kpi} ${k.v==='green'?s.kpiGreen:k.v==='red'?s.kpiRed:k.v==='orange'?s.kpiOrange:''}`}>
                        <div className={s.kpiBody}>
                          <div className={s.kpiLabel}>{k.label}</div>
                          <div className={s.kpiValue}>{k.value}<span className={s.kpiUnit}>{k.unit}</span></div>
                          {k.sub&&<div className={s.kpiSub}>{k.sub}</div>}
                        </div>
                      </div>
                    ))}
                  </div>

                  <div className={s.grid2}>
                    <div className={s.panel}>
                      <div className={s.panelTitle}>Execução Geral</div>
                      <div style={{display:'flex',alignItems:'center',gap:28}}>
                        <DonutChart dados={donutDados} total={relProg} size={130} thickness={20} label={{top:fmt1(relProg>0?relConc/relProg*100:0)+'%',bot:'executado'}}/>
                        <div>{donutDados.map((d,i)=>(
                          <div key={i} style={{display:'flex',alignItems:'center',gap:10,marginBottom:12}}>
                            <div style={{width:10,height:10,background:d.cor,borderRadius:2}}/>
                            <div><div style={{fontWeight:600,fontSize:13}}>{d.label}</div><div style={{fontFamily:'var(--mono)',fontSize:12,color:'var(--text3)'}}>{fmt4(d.val)} m³</div></div>
                          </div>
                        ))}
                        <div style={{fontFamily:'var(--mono)',fontSize:11,color:'var(--text3)',marginTop:8,paddingTop:8,borderTop:'1px solid var(--border)'}}>BTs faltando: {fmt4(prevVol.faltando)} m³</div>
                        </div>
                      </div>
                    </div>
                    <div className={s.panel}>
                      <div className={s.panelTitle}>Distribuição de Perdas</div>
                      <div style={{display:'flex',alignItems:'center',gap:28}}>
                        <DonutChart dados={donutPerda} total={pInfo.totalPrevisto||1} size={130} thickness={20} label={{top:fmt1(pInfo.indice)+'%',bot:'perda'}}/>
                        <div>{[{label:'Executado',cor:'var(--green)',val:pInfo.totalExecutado},{label:'Perda Obra',cor:'var(--red)',val:pInfo.perdaObra},{label:'Perda Caminhão',cor:'var(--orange)',val:Math.max(0,pInfo.perdaCaminhao)}].map((d,i)=>(
                          <div key={i} style={{display:'flex',alignItems:'center',gap:10,marginBottom:12}}>
                            <div style={{width:10,height:10,background:d.cor,borderRadius:2}}/>
                            <div><div style={{fontWeight:600,fontSize:13}}>{d.label}</div><div style={{fontFamily:'var(--mono)',fontSize:12,color:'var(--text3)'}}>{fmt4(d.val)} m³</div></div>
                          </div>
                        ))}</div>
                      </div>
                    </div>
                  </div>

                  <div className={s.panel}>
                    <div className={s.panelTitle}>Volume por Andar <span style={{fontSize:10,color:'var(--text3)',fontWeight:400}}>▼ clique para expandir</span></div>
                    <GraficoAndares pecas={pcs} lancamentos={lans} ordemAndares={ordemAndares} indicePerda={pInfo.indice}/>
                  </div>

                  <div className={s.panel}>
                    <div className={s.panelTitle}>Resumo por Tipo de Peça</div>
                    <div className={s.tableWrap}><table className={s.table}>
                      <thead><tr><th>Tipo</th><th>Qtd</th><th>Previsto</th><th>Executado</th><th>Faltando</th><th>%</th></tr></thead>
                      <tbody>{calcPorTipo(pcs,lans).map((t,i)=>(
                        <tr key={t.tipo}>
                          <td><div style={{display:'flex',alignItems:'center',gap:8}}><div style={{width:8,height:8,background:CORES[i%CORES.length],borderRadius:2}}/><span style={{fontWeight:600}}>{t.tipo}</span></div></td>
                          <td className={s.tdMono}>{t.count}</td>
                          <td className={s.tdMono}>{fmt4(t.prog)} m³</td>
                          <td className={s.tdGreen}>{fmt4(t.conc)} m³</td>
                          <td className={s.tdRed}>{fmt4(t.falt)} m³</td>
                          <td><div style={{display:'flex',alignItems:'center',gap:8}}><div style={{width:60,height:5,background:'var(--surface2)',borderRadius:3,overflow:'hidden'}}><div style={{height:'100%',width:`${Math.min(100,t.pct)}%`,background:t.pct>=100?'var(--green)':CORES[i%CORES.length]}}/></div><span className={s.tdMono}>{fmt1(t.pct)}%</span></div></td>
                        </tr>
                      ))}</tbody>
                    </table></div>
                  </div>

                  <div className={s.panel}>
                    <div className={s.panelTitle}>Índice Detalhado por BT</div>
                    <div className={s.tableWrap}><table className={s.table}>
                      <thead><tr><th>BT</th><th>Conc.</th><th>NF</th><th>Previsto</th><th>Executado</th><th>Perda Obra</th><th>Dif. Caminhão</th><th>Status</th></tr></thead>
                      <tbody>{bts.length===0?<tr><td colSpan={8} className={s.empty} style={{padding:'24px 16px'}}>Sem BTs configuradas</td></tr>
                        :bts.sort((a,b)=>a.numero-b.numero).map(b=>{
                          const conc=concretagens.find(c=>c.id===b.concretagemId);
                          const bLans=lans.filter(l=>l.btConfigId===b.id);
                          const usado=bLans.reduce((s,l)=>s+l.volume,0);
                          const perdaO=bLans.reduce((s,l)=>s+l.perdaObra,0);
                          const difCam=usado-b.volumePrevisto;
                          const lancada=bLans.length>0;
                          return(
                            <tr key={b.id}>
                              <td className={s.tdAccent}>BT-{b.numero}</td>
                              <td className={s.tdMono}>{conc?.numero||'—'}</td>
                              <td className={s.tdMono} style={{color:'var(--text2)'}}>{b.notaFiscal||'—'}</td>
                              <td className={s.tdMono}>{fmt4(b.volumePrevisto)}</td>
                              <td className={lancada?(difCam>0?s.tdBlue:s.tdGreen):s.tdMuted}>{lancada?fmt4(usado):'—'}</td>
                              <td className={perdaO>0?s.tdRed:s.tdMuted}>{lancada?fmt4(perdaO):'—'}</td>
                              <td className={lancada?(difCam>0?s.tdBlue:difCam<0?s.tdRed:s.tdMuted):s.tdMuted}>{lancada?(difCam>0?`▲ +${fmt4(difCam)}`:difCam<0?`▼ ${fmt4(Math.abs(difCam))}`:'—'):'—'}</td>
                              <td><span className={`${s.badge} ${lancada?s.badgeComplete:s.badgePending}`}>{lancada?'Lançada':'Pendente'}</span></td>
                            </tr>
                          );
                        })
                      }</tbody>
                    </table></div>
                  </div>
                </>
              );
            })()}
          </main>
        )}
      </div>

        {/* ══ CALCULAR CONCRETO ══ */}


        {/* ══ LEVANTAMENTO ══ */}
        {tab==='levantamento'&&<PageLevantamento pecas={pecas} onEnviar={msg=>showToast(msg,'ok')}/>}

      {tab==='notas'&&(
        <main className={`${s.page} animate-fadein`}>
          <div className={s.panel}>
            <div className={s.panelTitle}>📝 Notas de Versão</div>

            {[
              {
                versao: 'v1.0',
                data: '2026-05-20',
                status: 'atual',
                itens: [
                  'Dashboard operacional com KPIs em tempo real (Volume Projeto, Concretado, Faltando Real, Faltando Projeto, Índice de Perda)',
                  'Filtro por Andar e Concretagem com dropdown — andar filtra concretagens disponíveis',
                  'Progresso por Tipo de Peça clicável para expandir lista de peças individuais',
                  'Status das BTs por Concretagem com % de perda/sobra por BT',
                  'Lançar BT com steps: selecionar BT → peças & % (filtro por tipo) → fechamento (sobra/perda)',
                  'Editar BT já lançada — zerar ou corrigir valores',
                  'Gerenciar Peças: cadastro individual, importação em lote (colar TSV ou upload arquivo), baixar modelo Excel',
                  'Gerenciar Concretagens: criar, editar, excluir com vínculos de peças e BTs',
                  'Cálculo de perda: perda em obra + perda do caminhão (previsto − executado)',
                  'Sobra inesperada contabilizada como perda negativa no índice',
                  'Relatórios com gráficos: donuts de execução e perdas, gráfico de barras por andar, tabelas detalhadas',
                  'Filtro do relatório por concretagem e andar atualiza todos os dados e gráficos',
                  'Calcular Concreto: Pilar (Retangular, Redondo, Tipo L, Tipo T) e Rampa com esquemas visuais',
                  'Levantamento de Concreto: lista intermediária antes de enviar para a base de peças',
                  'Configuração da Obra: nome da obra, ordenação de andares (drag & drop, ▲▼, inverter), adicionar/remover andares',
                  'Seletor de andares centralizado — todas as telas usam a mesma base de andares',
                  'Suporte a volumes com vírgula decimal (formato BR da planilha Google Sheets)',
                  'Auto-refresh desativado — dados só atualizam ao clicar ↻ ou após ação',
                  'Logo e foto da obra na sidebar',
                ],
              },
            ].map(v=>(
              <div key={v.versao} style={{marginBottom:28}}>
                <div style={{display:'flex',alignItems:'center',gap:14,marginBottom:16,paddingBottom:12,borderBottom:'1px solid var(--border)'}}>
                  <div style={{fontFamily:'var(--mono)',fontSize:22,fontWeight:700,color:'var(--accent)'}}>{v.versao}</div>
                  <div style={{fontFamily:'var(--mono)',fontSize:12,color:'var(--text3)'}}>{v.data}</div>
                  {v.status==='atual'&&<span style={{background:'rgba(34,197,94,0.12)',color:'var(--green)',border:'1px solid rgba(34,197,94,0.2)',borderRadius:20,padding:'3px 12px',fontSize:11,fontWeight:700}}>✓ Versão Atual</span>}
                </div>
                <div style={{display:'flex',flexDirection:'column',gap:8}}>
                  {v.itens.map((item,i)=>(
                    <div key={i} style={{display:'flex',gap:12,alignItems:'flex-start',padding:'8px 12px',background:'var(--surface2)',borderRadius:'var(--radius-sm)',borderLeft:'2px solid var(--border2)'}}>
                      <span style={{color:'var(--accent)',fontWeight:700,flexShrink:0,marginTop:1}}>✓</span>
                      <span style={{fontSize:13,color:'var(--text2)',lineHeight:1.5}}>{item}</span>
                    </div>
                  ))}
                </div>
              </div>
            ))}

            <div style={{marginTop:20,padding:'14px 16px',background:'var(--bg2)',borderRadius:'var(--radius-sm)',border:'1px solid var(--border)',fontFamily:'var(--mono)',fontSize:11,color:'var(--text3)',lineHeight:1.8}}>
              Stack: Next.js 14 · Google Sheets (banco de dados) · Google Apps Script (API) · Vercel (deploy)<br/>
              Repositório: github.com/miltonfigueiredo97-lang/concreto-dashboard
            </div>
          </div>
        </main>
      )}

      {/* MODAIS */}
      <ModalCalcConcreto open={modalCalc} onClose={()=>setModalCalc(false)} levantamento={levantamento} setLevantamento={setLevantamento} config={config} pecas={pecas}/>
      <ModalLevantamento open={modalLevantamento} onClose={()=>setModalLevantamento(false)} levantamento={levantamento} setLevantamento={setLevantamento}
        onEnviarBase={async(itens)=>{
          try{
            const {apiAdicionarPecaLote}=await import('../lib/api');
            await apiAdicionarPecaLote(itens);
            showToast('✓ '+itens.length+' peças enviadas para a base!','ok');
            setModalLevantamento(false);
          }catch(e){showToast('Erro: '+e.message,'err');}
        }}/>
      <ModalPecas       open={modalPecas}  onClose={()=>setModalPecas(false)}  pecas={pecas} onSalvo={msg=>showToast(msg,'ok')}/>
      <ModalConcretagem open={modalConc}   onClose={()=>setModalConc(false)}   pecas={pecas} concretagens={concretagens} pecaConc={pecaConc} btsConfig={btsConfig} onSalvo={msg=>showToast(msg,'ok')}/>
      <ModalLancarBT    open={modalBT}     onClose={()=>setModalBT(false)}     pecas={pecas} concretagens={concretagens} pecaConc={pecaConc} btsConfig={btsConfig} lancamentos={lancamentos} onSalvo={msg=>showToast(msg,'ok')}/>
      <ModalConfig      open={modalConfig} onClose={()=>setModalConfig(false)} pecas={pecas} config={config} onSalvar={salvarConfig}/>
      <Toast msg={toast.msg} tipo={toast.tipo} onDone={()=>setToast({msg:'',tipo:'ok'})}/>
    </div>
  );
}